const scenarios3b = {
  18: [
    {
      text: "Beria has replaced Ezhov as head of the NKVD. Some prisoners from the Great Terror are being quietly released as Beria consolidates his own power by discrediting his predecessor. A former colleague you thought was dead reappears, rehabilitated. He asks you to vouch for other imprisoned comrades. How do you respond?",
      choices: [
        {text: "Welcome him warmly but refuse to vouch for anyone else — one miracle is enough.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.85, response: "You embrace your returned colleague but make no promises. Beria's selective releases are tactical, not humanitarian. Getting involved in rehabilitation cases draws NKVD attention you cannot afford."},
        {text: "Vouch for several imprisoned colleagues — if the wind has changed, help them now.", loyalty: -5, cunning: -5, reputation: 10, survival: 0.60, response: "You write letters supporting several prisoners. Some are released. But the NKVD notes your eagerness — why are you so connected to enemies of the people? Your file grows thicker."},
        {text: "Report the conversation to Beria's office — demonstrate your vigilance.", loyalty: 10, cunning: 5, reputation: -10, survival: 0.80, response: "You inform the NKVD about the approach. Your colleague is re-arrested within weeks. Beria appreciates your loyalty, but your reputation among survivors is destroyed."},
        {text: "Use the situation to approach Beria directly — offer to help him build cases against Ezhov's people.", loyalty: 10, cunning: 10, reputation: -5, survival: 0.75, response: "You offer Beria useful intelligence against Ezhov loyalists still in the apparatus. Beria values informants, but those who know too much about NKVD internal affairs often meet unfortunate ends."}
      ]
    },
    {
      text: "The Third Five-Year Plan is under discussion. The purges devastated industrial management — experienced engineers and factory directors were shot as 'wreckers.' Production has suffered. Young, inexperienced replacements struggle. Stalin demands the plan maintain ambitious targets despite the decimated cadres. What position do you take?",
      choices: [
        {text: "Endorse the ambitious targets — the new generation of Soviet-trained cadres will exceed all expectations.", loyalty: 10, cunning: 5, reputation: 0, survival: 0.85, response: "You praise the young replacements and promise spectacular results. The targets are approved. When they are not met, blame will fall on 'remaining wreckers' — never on the plan itself."},
        {text: "Quietly advocate for slightly reduced targets in closed committee sessions.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.80, response: "You argue for realism behind closed doors. Some targets are quietly adjusted downward while the public figures remain heroic. Pragmatism in private, enthusiasm in public — the Soviet way."},
        {text: "Volunteer to personally oversee industrial recovery in a key sector.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You take direct responsibility for a critical industry. If production recovers, you are a hero. If it fails, you are a scapegoat. But having a concrete job makes you harder to purge without disrupting output."},
        {text: "Suggest that the purge of 'wreckers' may have gone too far — we lost valuable specialists.", loyalty: -10, cunning: -15, reputation: 5, survival: 0.50, response: "You imply the Terror damaged industrial capacity. This is obviously true but unsayable. Questioning the purges means questioning Stalin's judgment. Several delegates edge away from you physically."}
      ]
    },
    {
      text: "The Soviet-Japanese border conflict at Khalkhin Gol in Mongolia is escalating. Zhukov has been given command and requests massive reinforcements. Some in the military argue that resources should be conserved for the inevitable European war. The Red Army officer corps was devastated by the purge of Tukhachevsky and other generals. How do you weigh in?",
      choices: [
        {text: "Support Zhukov's request for reinforcements — a decisive victory will deter Japanese aggression.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You back Zhukov's aggressive approach. The battle at Khalkhin Gol becomes a stunning Soviet victory that keeps Japan from attacking Siberia during the coming war. You backed the right horse."},
        {text: "Argue for a diplomatic solution — we cannot fight on two fronts.", loyalty: 0, cunning: 5, reputation: 5, survival: 0.80, response: "You counsel caution. It is a reasonable position, but Stalin wants to teach Japan a lesson. When Zhukov wins decisively, your caution looks timid."},
        {text: "Use the crisis to advocate for accelerated military production regardless of the cost.", loyalty: 10, cunning: 5, reputation: 0, survival: 0.85, response: "You push for emergency military spending. With war looming in Europe and fighting in the East, no one can argue against rearmament. Aligning with the military-industrial priority is safe."},
        {text: "Raise concerns about the Red Army's readiness after the purge of its officer corps.", loyalty: -10, cunning: -10, reputation: 10, survival: 0.55, response: "You point out that shooting 35,000 officers has weakened the army. This is blindingly obvious to everyone but cannot be said aloud. Stalin takes criticism of the military purge as criticism of himself."}
      ]
    },
    {
      text: "The Spanish Civil War has ended in defeat for the Republic. Soviet advisors and International Brigade volunteers are returning. Some Spanish Communist refugees seek asylum in the USSR. Meanwhile, NKVD agents in Spain conducted their own purge — assassinating Trotskyists and anarchists within the Republican side. You encounter a returning Soviet officer who witnessed NKVD murders of Spanish leftists.",
      choices: [
        {text: "Tell the officer to forget everything he saw in Spain — silence is survival.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.85, response: "You give the bluntest possible advice. Many Spanish veterans who talk about what they witnessed disappear. Your counsel may save his life, and keeping your distance protects yours."},
        {text: "Report the officer's knowledge to the NKVD — they will want to ensure his silence.", loyalty: 10, cunning: 5, reputation: -10, survival: 0.80, response: "You inform Beria's people about a potential security leak. The officer is quietly transferred to a remote posting. The NKVD appreciates your vigilance, though you have likely condemned a comrade."},
        {text: "Help the Spanish refugees integrate — show socialist solidarity.", loyalty: 5, cunning: 0, reputation: 10, survival: 0.75, response: "You assist Spanish Communist refugees in finding housing and work. This humanitarian gesture earns you respect, but association with foreigners always carries risk in Stalin's USSR."},
        {text: "Use your knowledge of Spanish events to write an article praising Soviet intervention as heroic.", loyalty: 10, cunning: 10, reputation: 0, survival: 0.85, response: "You craft a narrative of heroic Soviet support for the Spanish Republic, omitting the NKVD's internal purge. The article is published in Pravda. Controlling the narrative is always rewarded."}
      ]
    },
    {
      text: "The Soviet invasion of eastern Poland under the Molotov-Ribbentrop Pact is underway. The NKVD follows close behind the army, compiling lists of Polish officers, intellectuals, and officials. You receive classified orders regarding the disposition of Polish prisoners of war. The scale of what is being planned is chilling. Over 20,000 Polish officers will be murdered at Katyn and other sites.",
      choices: [
        {text: "Carry out your role in the operation without question — orders are orders.", loyalty: 10, cunning: 10, reputation: -10, survival: 0.85, response: "You participate in the machinery of the Katyn massacre. The secret will be kept for decades, blamed on the Nazis. Your complicity binds you to the regime — you can never defect or speak freely again."},
        {text: "Request a transfer to other duties — distance yourself from the Polish operation.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.80, response: "You arrange a reassignment to economic planning work, avoiding direct involvement. Not everyone can escape the dirty work, but those with connections and foresight manage it."},
        {text: "Document what you witness in a private journal hidden from the NKVD.", loyalty: -5, cunning: -5, reputation: 5, survival: 0.60, response: "You secretly record what is happening. If discovered, this journal is a death sentence. It will either be destroyed, or surface decades later as evidence of the crime."},
        {text: "Throw yourself into the 'liberation' narrative — the Red Army is freeing Ukrainians and Belarusians from Polish oppression.", loyalty: 10, cunning: 5, reputation: 0, survival: 0.85, response: "You enthusiastically promote the propaganda line that the invasion liberates brotherly peoples. The narrative is useful. The reality in the forests of Katyn is something else entirely."}
      ]
    },
    {
      text: "The annexation of the Baltic states is being prepared. Lithuania, Latvia, and Estonia will be absorbed into the USSR through rigged elections and manufactured 'requests' to join. You are assigned to the commission overseeing the process in one of the republics. Local Communist parties are small and weak — most Balts are hostile to Soviet rule.",
      choices: [
        {text: "Execute the annexation plan efficiently — install loyal cadres and suppress resistance.", loyalty: 10, cunning: 10, reputation: -5, survival: 0.85, response: "You oversee the manufactured plebiscites and the installation of puppet governments. The process goes smoothly on paper. The deportations that follow will create hatred that persists for fifty years."},
        {text: "Recommend a gentler approach — win the population over gradually rather than through force.", loyalty: -5, cunning: 5, reputation: 5, survival: 0.70, response: "You suggest a softer integration strategy. Moscow has no patience for gradualism. The deportation trains are already scheduled. Your moderation is noted as weakness."},
        {text: "Focus on the economic aspects — inventory Baltic industrial assets for integration into the Soviet economy.", loyalty: 5, cunning: 10, reputation: 0, survival: 0.85, response: "You concentrate on the practical work of economic integration, leaving the political repression to the NKVD. Being the accountant rather than the executioner is a form of survival."},
        {text: "Request reassignment — you do not want to be involved in this operation.", loyalty: -5, cunning: 0, reputation: 5, survival: 0.65, response: "You try to avoid the assignment. This is interpreted as political unreliability. In Stalin's system, refusing a task is almost as dangerous as failing at one."}
      ]
    },
    {
      text: "Stalin is reorganizing the military command structure in anticipation of war. The lessons of Finland's Winter War have been humbling — the Red Army performed poorly against tiny Finland. Voroshilov, the Defense Commissar and Stalin's old crony, is clearly incompetent. Timoshenko is replacing him. You sit on a military review commission assessing readiness.",
      choices: [
        {text: "Present an honest assessment of military deficiencies — the army needs drastic reform.", loyalty: 0, cunning: 5, reputation: 10, survival: 0.70, response: "You detail equipment shortages, poor officer training, and doctrinal failures. Stalin actually listens — the Finnish debacle has shaken him. But messengers bearing bad news remain at risk."},
        {text: "Blame the Finnish failures on 'remaining enemies' in the officer corps — call for another round of purges.", loyalty: 10, cunning: 0, reputation: -10, survival: 0.75, response: "You attribute military failure to sabotage rather than systemic problems. This satisfies ideological requirements but does nothing to actually fix the army. More innocent officers are arrested."},
        {text: "Support Timoshenko's reforms while carefully praising Voroshilov's past contributions.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You navigate the personnel change perfectly — backing the new man while not humiliating the old one who remains a Stalin favorite. Voroshilov keeps his Politburo seat. Discretion serves you well."},
        {text: "Advocate for the rehabilitation of purged military officers — we need experienced commanders.", loyalty: -5, cunning: 0, reputation: 10, survival: 0.55, response: "You suggest recalling imprisoned officers to active duty. Some, like Rokossovsky, are indeed pulled from the camps. But advocating for purge victims remains dangerous — you are questioning the Terror itself."}
      ]
    },
    {
      text: "A new wave of propaganda demands that Soviet citizens prepare for possible war while simultaneously celebrating the 'genius' of the Molotov-Ribbentrop Pact. You are tasked with giving a speech to a major factory workforce. Workers are confused — yesterday Germany was the fascist enemy, today it is a partner. Some workers have relatives who fought fascists in Spain.",
      choices: [
        {text: "Explain the Pact as Stalin's brilliant maneuver to buy time while the capitalists destroy each other.", loyalty: 10, cunning: 10, reputation: 0, survival: 0.90, response: "You deliver the approved line with conviction. The workers nod along. Whether they believe it is irrelevant — the performance of belief is what matters in the Soviet system."},
        {text: "Focus your speech on military readiness and patriotic duty rather than trying to justify the Pact.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You sidestep the ideological gymnastics and appeal to patriotism and preparedness. Workers respond better to concrete calls for vigilance than to tortured explanations of diplomatic reversals."},
        {text: "Acknowledge that the Pact is confusing but insist that Comrade Stalin sees further than ordinary mortals.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.85, response: "You admit the confusion while demanding faith in the leader. This crude appeal to authority is the standard Soviet response to cognitive dissonance. It works well enough."},
        {text: "Speak honestly about the difficulty of the international situation without endorsing any particular line.", loyalty: -5, cunning: -5, reputation: 10, survival: 0.65, response: "You give a nuanced, thoughtful speech that stops short of full-throated endorsement. Workers appreciate your honesty. The party minder in the audience does not. Your speech is reported upward."}
      ]
    }
  ],
  19: [
    {
      text: "Malenkov delivers the main political report at the Congress instead of Stalin — a sign that he is being groomed as successor. But Stalin's intentions are unreadable. Khrushchev, Beria, and others watch jealously. You must decide whom to cultivate as the succession crisis looms beneath the surface.",
      choices: [
        {text: "Attach yourself to Malenkov — he appears to be Stalin's chosen heir.", loyalty: 5, cunning: 10, reputation: 0, survival: 0.80, response: "You cultivate Malenkov's circle. He does emerge as the initial successor after Stalin dies, but Khrushchev outmaneuvers him within two years. You bet on the wrong horse."},
        {text: "Maintain equidistance from all potential successors — loyalty to Stalin alone.", loyalty: 10, cunning: 15, reputation: 0, survival: 0.85, response: "You refuse to join any faction, pledging loyalty only to Stalin. This is the safest position while Stalin lives. When he dies, you will need to choose quickly — but at least you have no enemies."},
        {text: "Quietly build ties with Khrushchev — he controls the party apparatus in Moscow and Ukraine.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.85, response: "You recognize Khrushchev's underestimated organizational power. After Stalin's death, Khrushchev's control of the party apparatus proves decisive. Your early investment pays off."},
        {text: "Ally with Beria — the NKVD chief is the most powerful individual after Stalin.", loyalty: 5, cunning: 5, reputation: -10, survival: 0.65, response: "You cultivate Beria, the feared security chief. After Stalin's death, Beria makes a bold play for power — and is arrested and shot by his colleagues within months. His allies are purged."}
      ]
    },
    {
      text: "The Mingrelian Affair is targeting Georgian officials close to Beria. Stalin appears to be building a case against his own secret police chief. Arrests are mounting in Georgia. Beria maintains a calm exterior at the Congress but his position is precarious. You have professional connections in the Georgian party.",
      choices: [
        {text: "Sever all connections with Georgian officials immediately — the Mingrelian Affair is radioactive.", loyalty: 0, cunning: 15, reputation: -5, survival: 0.90, response: "You cut ties with every Georgian contact. When the Mingrelian Affair expands, your clean hands protect you. In Stalin's final years, guilt by association is a death sentence."},
        {text: "Provide information about your Georgian contacts to the investigators — demonstrate loyalty.", loyalty: 10, cunning: 5, reputation: -10, survival: 0.80, response: "You offer the investigators details about Georgian officials you know. This earns you credit with Stalin's apparatus but makes a permanent enemy of Beria, who will briefly hold supreme power after Stalin dies."},
        {text: "Quietly warn your Georgian contacts about the investigations.", loyalty: -5, cunning: 0, reputation: 10, survival: 0.55, response: "You tip off friends in Georgia. If discovered, this is obstruction of a state security investigation — effectively treason. Your humanitarian impulse could get you killed."},
        {text: "Ignore the Georgian situation entirely and focus your Congress speech on industrial achievements.", loyalty: 0, cunning: 10, reputation: 0, survival: 0.85, response: "You deliver a thoroughly unremarkable speech about production statistics. The Mingrelian Affair rages around you while you discuss steel output. Boring speeches save lives."}
      ]
    },
    {
      text: "The Anti-Cosmopolitan Campaign targets Jewish intellectuals, scientists, and cultural figures. The Jewish Anti-Fascist Committee has been dissolved and its members arrested. Coded anti-Semitic language fills the press — references to 'rootless cosmopolitans' and 'bourgeois nationalists.' Jewish colleagues at your workplace are being dismissed. What do you do?",
      choices: [
        {text: "Participate actively in the campaign — denounce cosmopolitan influences in your field.", loyalty: 10, cunning: 5, reputation: -15, survival: 0.85, response: "You join the anti-cosmopolitan crusade, denouncing Jewish colleagues by their birth names. When Stalin dies and the campaign is abandoned, your enthusiastic participation will be remembered — by the victims."},
        {text: "Do the minimum required — attend the meetings but volunteer nothing.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.85, response: "You attend the required denunciation sessions and remain silent. You neither persecute nor protect. The moral cowardice of the bystander — but bystanders survive."},
        {text: "Quietly help affected Jewish colleagues find positions in less visible institutions.", loyalty: -5, cunning: 5, reputation: 10, survival: 0.65, response: "You discreetly arrange transfers and recommendations for targeted colleagues. This is genuinely courageous. If the NKVD discovers your efforts, you will be accused of shielding enemies."},
        {text: "Write a theoretical article distinguishing legitimate cultural criticism from anti-Semitism.", loyalty: -10, cunning: -10, reputation: 15, survival: 0.50, response: "You attempt to thread an impossible needle, criticizing cosmopolitanism in theory while defending Jewish colleagues in practice. The article satisfies no one and draws dangerous attention to your sympathies."}
      ]
    },
    {
      text: "The Korean War rages on the peninsula. Stalin has supported Kim Il-sung's invasion of South Korea, and now Chinese volunteers are fighting American forces. Soviet pilots secretly fly combat missions over Korea in MiG-15s with Chinese markings. A downed Soviet pilot could trigger World War III. You learn of the secret air operations through your military contacts.",
      choices: [
        {text: "Say nothing about what you know — this is a state secret of the highest order.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You keep the secret absolutely. Demonstrating that you can be trusted with sensitive military information enhances your standing with the security establishment. Silence is golden."},
        {text: "Use your knowledge to advocate for better pilot rotation to reduce the risk of capture.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You discreetly suggest operational improvements to reduce the chance of a Soviet pilot being captured alive. This practical contribution shows you are useful without being threatening."},
        {text: "Raise concerns in a closed session about the risks of direct confrontation with America.", loyalty: -5, cunning: 5, reputation: 5, survival: 0.70, response: "You warn about nuclear escalation risks. Stalin dismisses such caution as defeatism. The Soviet leadership believes American nuclear monopoly has ended and the correlation of forces favors boldness."},
        {text: "Enthusiastically support expanding Soviet involvement — help crush American imperialism in Asia.", loyalty: 10, cunning: 0, reputation: 0, survival: 0.80, response: "You advocate escalation in Korea. Stalin appreciates the enthusiasm, but he is actually more cautious than his rhetoric suggests — he does not want a direct war with America. Your hawkishness overshoots the leader's position."}
      ]
    },
    {
      text: "Stalin's new theoretical work 'Economic Problems of Socialism in the USSR' has been published before the Congress. It is rambling and confused, but every delegate must study and praise it. Voznesensky, the brilliant economic planner who dared to suggest alternative approaches, was already shot in the Leningrad Affair. The message is clear: there is only one economist in the USSR.",
      choices: [
        {text: "Deliver an effusive tribute to Stalin's economic genius — call it a new epoch in Marxist theory.", loyalty: 15, cunning: 5, reputation: -5, survival: 0.85, response: "You praise the work extravagantly. Your speech joins dozens of identical tributes. The competition to flatter most elaborately is the only real contest at this Congress."},
        {text: "Write a detailed analysis applying Stalin's economic ideas to your specific sector.", loyalty: 10, cunning: 10, reputation: 5, survival: 0.90, response: "You produce a serious engagement with the text, showing how its principles could guide policy in your area. This demonstrates both loyalty and competence — a rare combination that Stalin values."},
        {text: "Praise the work briefly and pivot to concrete economic proposals for the new Five-Year Plan.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You pay the obligatory tribute and move to practical matters. Being useful is your shield. The Five-Year Plan needs people who can actually manage an economy."},
        {text: "Privately note to a colleague that the work contradicts some of Marx's positions.", loyalty: -15, cunning: -15, reputation: 5, survival: 0.50, response: "You commit the cardinal sin of intellectual honesty in Stalin's court. Even a private observation can be reported. Voznesensky was shot for less. Your theoretical integrity may be your death warrant."}
      ]
    },
    {
      text: "The Congress votes to rename the Politburo to the Presidium and expands it from 11 to 25 full members. Everyone understands this dilutes the power of the old guard — Molotov, Mikoian, Voroshilov, Kaganovich. New, younger faces appear. You are asked your opinion on the restructuring in a corridor conversation by an old Politburo member who is clearly anxious.",
      choices: [
        {text: "Praise the expansion as a deepening of collective leadership and inner-party democracy.", loyalty: 10, cunning: 10, reputation: 0, survival: 0.85, response: "You parrot the official justification. The anxious old guard member looks at you with contempt but says nothing. In four months Stalin will be dead and the expansion reversed. But you could not have known that."},
        {text: "Sympathize privately but warn against any organized resistance — Stalin is too dangerous.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.80, response: "You counsel patience to the worried veteran. Any organized opposition to Stalin would be suicidal. Better to wait and see — which is exactly what the old guard does. Stalin dies before he can strike."},
        {text: "Distance yourself from the conversation — being seen with anxious old guard members is dangerous.", loyalty: 5, cunning: 15, reputation: -5, survival: 0.90, response: "You excuse yourself and walk away. Proximity to the threatened is itself threatening. Cold calculation dictates avoiding anyone in Stalin's crosshairs during these final paranoid months."},
        {text: "Offer to serve on the expanded Presidium — position yourself as one of the new blood.", loyalty: 10, cunning: 10, reputation: -5, survival: 0.80, response: "You volunteer for the expanded body, aligning with Stalin's apparent intent to replace the old guard. If Stalin had lived, this would have been brilliant. His death in March 1953 makes the expanded Presidium irrelevant."}
      ]
    },
    {
      text: "The Doctors' Plot is reaching fever pitch. Prominent physicians — most of them Jewish — are accused of plotting to murder Soviet leaders through medical sabotage. Pravda publishes hysterical articles. The public atmosphere recalls 1937. Some fear a new mass purge is being prepared, possibly including mass deportation of Jews to Siberia.",
      choices: [
        {text: "Publicly demand harsh punishment for the 'murderer-doctors' at the Congress.", loyalty: 10, cunning: 0, reputation: -15, survival: 0.70, response: "You ride the wave of hysteria. But Stalin dies on March 5, 1953 — just weeks after the Congress. The Doctors' Plot is immediately exposed as fabricated. Those most vocally associated with it face disgrace."},
        {text: "Express support for the investigation in the mildest possible terms — do not get out ahead of events.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You offer tepid support for 'vigilance' without committing to the specifics of the Doctors' Plot. When the plot is debunked after Stalin's death, your restrained position leaves you uncompromised."},
        {text: "Request your own personal physician be investigated — demonstrate that you trust no one.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.80, response: "You make a theatrical gesture of suspicion toward your own doctor. The absurdity is lost on the Congress audience. Performative paranoia is expected in this atmosphere."},
        {text: "Say nothing about the Doctors' Plot and speak only about agricultural production targets.", loyalty: 0, cunning: 10, reputation: 0, survival: 0.85, response: "You give an entire Congress speech without mentioning the biggest political story of the moment. Some see this as suspicious evasion. Others do not notice. Either way, you have left no damaging record."}
      ]
    },
    {
      text: "In the corridors of the Congress, you observe something remarkable: the aging Politburo members are terrified of each other. Molotov's wife is in a labor camp. Mikoian has been publicly attacked. Voroshilov is suspected of being a British agent. Even Beria seems nervous. Stalin has set his inner circle against itself. A colleague whispers: 'The old man has gone mad.'",
      choices: [
        {text: "Walk away immediately — you heard nothing.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.90, response: "You turn and leave without responding. The colleague's remark, if reported, would be fatal — for both of you. Your refusal to engage is the wisest possible response in this environment."},
        {text: "Report the remark to security — even whispered treason must be punished.", loyalty: 15, cunning: 5, reputation: -15, survival: 0.80, response: "You denounce your colleague. He is arrested. But denunciations create chains — your colleague may name others under interrogation, and the web of suspicion may eventually reach you."},
        {text: "Nod silently and change the subject to something trivial.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.85, response: "You acknowledge the remark with a meaningful look but steer the conversation to the weather. You have neither endorsed nor reported the comment. A gray zone that most Soviet officials inhabit daily."},
        {text: "Whisper back: 'We must endure. It cannot last much longer.'", loyalty: -5, cunning: 0, reputation: 10, survival: 0.60, response: "You offer furtive solidarity. It is a deeply human response. Stalin will indeed die in four months. But you have given your colleague something to report if he is ever under pressure to name conspirators."}
      ]
    }
  ],
  20: [
    {
      text: "The rehabilitation of purge victims has begun. Thousands of files are being reviewed. You sit on a commission examining cases from the 1930s Terror. The files reveal that some of your current colleagues signed denunciations that led to executions. Do you expose them?",
      choices: [
        {text: "Expose the denouncers — the truth must come out as part of de-Stalinization.", loyalty: 0, cunning: -5, reputation: 15, survival: 0.65, response: "You reveal the complicity of current officials. This creates powerful enemies. Many of those who signed denunciations now hold high positions. They will fight to prevent their exposure."},
        {text: "Quietly file the information without acting on it — keep it as political insurance.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.90, response: "You note who signed what and file the knowledge away. Kompromat is the currency of Soviet politics. You now have leverage over colleagues without having made enemies."},
        {text: "Focus the commission's work on rehabilitating victims rather than punishing perpetrators.", loyalty: 5, cunning: 10, reputation: 10, survival: 0.85, response: "You direct the commission toward justice for the dead rather than punishment for the living. This is Khrushchev's preferred approach — limited accountability preserves the system."},
        {text: "Suppress the most damaging files — too many revelations could destabilize the entire party.", loyalty: 10, cunning: 5, reputation: -10, survival: 0.80, response: "You quietly remove the most explosive documents. The party leadership appreciates your discretion. Many of the guilty escape accountability entirely, which is exactly what the leadership wants."}
      ]
    },
    {
      text: "The Polish October unfolds. Gomulka returns to power in Poland, asserting a degree of independence from Moscow. Khrushchev flies to Warsaw in a rage, Soviet troops move toward the capital, but ultimately a compromise is reached. The Polish crisis is less dramatic than Hungary but equally significant. You advise the Presidium on the Polish situation.",
      choices: [
        {text: "Counsel acceptance of Gomulka — a reformist Communist is better than an anti-Communist revolution.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You advocate the position that ultimately prevails: let Poland have its own path to socialism as long as it remains in the Warsaw Pact. Pragmatism wins over dogmatism. Your advice proves correct."},
        {text: "Demand military intervention — any deviation from Soviet control sets a dangerous precedent.", loyalty: 10, cunning: 0, reputation: -5, survival: 0.75, response: "You advocate military force. Khrushchev initially inclines this way but backs down. Your hawkishness is noted but you end up on the losing side of the argument."},
        {text: "Propose economic concessions to Poland — buy loyalty with trade terms and debt forgiveness.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You suggest an economic approach to the crisis. Some concessions are indeed made. The economic dimension of bloc management is often overlooked in favor of military drama, but it matters."},
        {text: "Use the Polish crisis to argue that de-Stalinization must be slowed before it destabilizes other satellites.", loyalty: 0, cunning: 10, reputation: 0, survival: 0.85, response: "You draw a direct line from the Secret Speech to Polish and Hungarian unrest. This argument has force — even Khrushchev privately worries he has opened Pandora's box."}
      ]
    },
    {
      text: "De-Stalinization is causing turmoil within the Soviet intelligentsia. Literary journals publish works that were unthinkable under Stalin. 'Not by Bread Alone' by Dudintsev criticizes the bureaucracy. Students at Moscow University hold unauthorized discussion groups. The cultural thaw thrills reformers and terrifies conservatives. Where do you stand on cultural liberalization?",
      choices: [
        {text: "Support the cultural thaw — socialist realism was a creative prison that weakened Soviet culture.", loyalty: 5, cunning: 0, reputation: 10, survival: 0.75, response: "You champion cultural liberalization. Khrushchev himself has ambivalent feelings about the thaw — he encourages it one day and restricts it the next. Your position depends on his mood."},
        {text: "Warn that cultural liberalization is going too far — the party must maintain ideological guidance.", loyalty: 5, cunning: 10, reputation: -5, survival: 0.85, response: "You counsel restraint. This aligns with the conservative wing and with Khrushchev's own periodic retreats from liberalization. Being a voice of caution on culture is rarely punished."},
        {text: "Focus on scientific and technical culture rather than literary politics — promote the Soviet space program.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.90, response: "You redirect cultural energy toward science and technology. The space program is an area where Soviet achievements are genuine and uncontroversial. Sputnik will launch the following year."},
        {text: "Propose establishing a commission to set clear boundaries for permissible cultural expression.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.85, response: "You try to institutionalize the thaw with clear rules. This appeals to the bureaucratic instinct. In practice, the boundaries remain arbitrary and dependent on Khrushchev's personal taste."}
      ]
    },
    {
      text: "Khrushchev is consolidating power. Molotov, Malenkov, and Kaganovich are increasingly marginalized. They will soon form the 'Anti-Party Group' to try to oust Khrushchev. You sense the factional lines hardening. Khrushchev is wooing the military — Marshal Zhukov is a key ally. Which side do you choose before the storm breaks?",
      choices: [
        {text: "Firmly commit to Khrushchev — he has the momentum and the party apparatus.", loyalty: 10, cunning: 10, reputation: 0, survival: 0.90, response: "You place your bet on Khrushchev. When the Anti-Party Group strikes in June 1957, Khrushchev survives by appealing to the full Central Committee. Your early loyalty is rewarded."},
        {text: "Maintain ties to both sides — hedge your bets until the outcome is clear.", loyalty: 0, cunning: 10, reputation: -5, survival: 0.80, response: "You keep channels open to both factions. This seems clever but when the crisis comes, Khrushchev demands to know who stood with him. Fence-sitters are not rewarded."},
        {text: "Side with Molotov and Malenkov — they represent experience and stability.", loyalty: -10, cunning: -5, reputation: 0, survival: 0.55, response: "You back the old guard. They have a Presidium majority but Khrushchev outflanks them by convening the full Central Committee. The Anti-Party Group is defeated and you share their disgrace."},
        {text: "Focus on cultivating Zhukov — the military is the decisive swing factor.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.80, response: "You build ties with Zhukov, who proves crucial in defeating the Anti-Party Group. But Khrushchev then dismisses Zhukov himself for 'Bonapartism.' Your military patron falls four months after his triumph."}
      ]
    },
    {
      text: "The Virgin Lands campaign is Khrushchev's signature agricultural program — plowing up millions of hectares of steppe in Kazakhstan and Siberia. Initial results are spectacular, with bumper wheat harvests. Khrushchev wants to expand the program further. Agricultural scientists warn about soil erosion and unsustainability. You oversee agricultural policy in your region.",
      choices: [
        {text: "Enthusiastically endorse expansion of the Virgin Lands — the results speak for themselves.", loyalty: 10, cunning: 0, reputation: 0, survival: 0.80, response: "You champion the program. The early harvests are genuine successes. But within years, dust storms and soil depletion will devastate the virgin lands. Short-term enthusiasm masks long-term disaster."},
        {text: "Support the program cautiously while quietly funding soil conservation research.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You praise the program publicly while privately investing in sustainable practices. When the virgin lands begin to fail, your region has a fallback. Hedging the agricultural bet is wise."},
        {text: "Present data suggesting the program has reached its natural limits and should not expand further.", loyalty: -5, cunning: 0, reputation: 10, survival: 0.70, response: "You argue against expansion based on agronomic evidence. Khrushchev is irritated by naysayers. The Virgin Lands are his pride and he does not accept limitations on his vision."},
        {text: "Propose complementary programs — irrigation, fertilizer production, mechanization — to support the Virgin Lands.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You suggest investments that would make the Virgin Lands sustainable. This shows both support for the program and practical wisdom. It is the kind of constructive contribution that earns respect."}
      ]
    },
    {
      text: "Tito's Yugoslavia is being rehabilitated after the break with Stalin. Khrushchev visits Belgrade and apologizes for Stalin's treatment of Yugoslavia. Some Soviet officials are uncomfortable — Tito represents an independent path to socialism that challenges Moscow's monopoly on Marxist truth. The Chinese are particularly hostile to the rapprochement.",
      choices: [
        {text: "Support reconciliation with Yugoslavia — socialist unity is more important than old grudges.", loyalty: 10, cunning: 5, reputation: 5, survival: 0.85, response: "You back Khrushchev's Yugoslav diplomacy. Reconciliation with Tito strengthens the socialist camp, even if it implicitly admits Stalin was wrong. Your support for the current line is noted."},
        {text: "Express reservations — Tito's model of worker self-management is revisionist and dangerous.", loyalty: -5, cunning: 5, reputation: 0, survival: 0.75, response: "You echo Chinese concerns about Yugoslav revisionism. This puts you at odds with Khrushchev's current policy but aligns you with conservative forces that will become more powerful."},
        {text: "Study Yugoslav economic reforms to identify useful ideas for the Soviet economy.", loyalty: 5, cunning: 10, reputation: 10, survival: 0.85, response: "You approach Yugoslavia as a laboratory of socialist alternatives. Some Yugoslav ideas about enterprise autonomy will influence Kosygin's reforms a decade later. Your intellectual curiosity is ahead of its time."},
        {text: "Use the Yugoslav question to position yourself as a bridge between Soviet and foreign Communist parties.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You develop expertise in inter-party relations, making yourself useful in the increasingly complex world of socialist diplomacy. Specialists in foreign communist affairs are always needed."}
      ]
    },
    {
      text: "The Geneva Summit of 1955 between Eisenhower and Khrushchev introduced the 'Spirit of Geneva' — a thaw in Cold War tensions. But the U-2 spy plane controversy looms ahead. The Soviet military demands increased defense spending. Khrushchev wants to reduce conventional forces and rely on nuclear deterrence, freeing resources for consumer goods. The marshals are furious.",
      choices: [
        {text: "Back Khrushchev's military cuts — the money is better spent on housing and consumer goods.", loyalty: 10, cunning: 5, reputation: 5, survival: 0.85, response: "You support shifting resources from guns to butter. Khrushchev appreciates your backing, but the military establishment resents civilians who advocate cutting their budgets."},
        {text: "Side with the marshals — conventional forces cannot be replaced by nuclear weapons alone.", loyalty: -5, cunning: 5, reputation: 5, survival: 0.75, response: "You back the military's position. Khrushchev overrides the generals and reduces conventional forces anyway. Your opposition is noted but not severely punished in the post-Stalin thaw."},
        {text: "Propose a compromise — modest military cuts paired with nuclear modernization.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You bridge the gap between the leader and the military. Something close to your compromise is actually adopted. Being the person who finds middle ground is invaluable."},
        {text: "Focus the debate on the space program — military rockets can serve peaceful purposes too.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You advocate for the dual-use rocket program. The same missiles that carry warheads will carry Sputnik and Gagarin. Framing military technology as peaceful achievement is brilliant messaging."}
      ]
    },
    {
      text: "Beria was arrested and executed in 1953, accused of being a 'British agent' and 'enemy of the people.' The charges were absurd — Beria's real crime was making a play for supreme power after Stalin's death. His trial was a closed military affair. Now, during the Congress, some delegates quietly question whether the methods used against Beria were any different from Stalin's show trials.",
      choices: [
        {text: "Defend Beria's execution — he was a genuine criminal who terrorized the party.", loyalty: 10, cunning: 10, reputation: 0, survival: 0.85, response: "You argue that Beria's fate was justified by his decades of crimes, regardless of the legal formalities. This is the official position and the one most of the leadership prefers."},
        {text: "Suggest that Beria should have been given a proper public trial with legal representation.", loyalty: -5, cunning: -5, reputation: 10, survival: 0.70, response: "You argue for the rule of law even for the worst criminals. This principled position makes some colleagues uncomfortable — a public trial might have revealed too much about everyone's complicity."},
        {text: "Avoid the topic entirely — Beria's case is closed and should not be reopened.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You steer every conversation away from the Beria question. The details of his arrest and execution are uncomfortable for everyone involved. Silence serves the collective interest."},
        {text: "Use the Beria case to argue for reforming the security services to prevent any future concentration of police power.", loyalty: 5, cunning: 10, reputation: 10, survival: 0.85, response: "You channel the Beria discussion toward institutional reform. Breaking the KGB's independence and subjecting it to party control is something the entire leadership supports. A constructive position."}
      ]
    }
  ],
  21: [
    {
      text: "Khrushchev has defeated the Anti-Party Group — Molotov, Malenkov, and Kaganovich are expelled from the leadership and sent to minor posts. Molotov becomes ambassador to Mongolia, Malenkov manages a power plant in Kazakhstan. The humiliation is deliberate but, unlike Stalin's era, they are not shot. You helped Khrushchev win. Now he wants your help deciding the fates of the defeated.",
      choices: [
        {text: "Advocate for harsher punishment — expulsion from the party entirely.", loyalty: 10, cunning: 0, reputation: -5, survival: 0.80, response: "You push for severity. Khrushchev prefers to humiliate rather than destroy — it shows the new era is different from Stalin's. Your bloodthirstiness is slightly out of step with the Thaw."},
        {text: "Support Khrushchev's moderate approach — disgrace but not destruction.", loyalty: 10, cunning: 10, reputation: 5, survival: 0.90, response: "You endorse sending the defeated to obscure postings. This demonstrates that Soviet power struggles no longer end in executions. You understand and support the new political culture Khrushchev is building."},
        {text: "Quietly maintain contact with the disgraced leaders — political fortunes can reverse.", loyalty: -5, cunning: 10, reputation: 0, survival: 0.75, response: "You keep a discreet channel open to Mongolia and Kazakhstan. These old Bolsheviks have no path back to power, making your continued contact pointless at best and suspicious at worst."},
        {text: "Use the Anti-Party Group's defeat to advance your own allies into the vacated positions.", loyalty: 5, cunning: 15, reputation: -5, survival: 0.90, response: "You move your people into positions left vacant by the purge. In the reshuffling that follows every factional victory, those who act fastest gain the most. You consolidate your network."}
      ]
    },
    {
      text: "Sputnik has been launched, shocking the world. The Soviet Union has beaten America into space. Khrushchev is triumphant — he uses the space program as proof that socialism is technologically superior. The rocket designer Korolev is a state secret, publicly unnamed. Khrushchev wants to set ever more ambitious space targets. The military sees rockets as weapons; the scientists see them as exploration.",
      choices: [
        {text: "Champion the space program's propaganda value — every launch proves the superiority of socialism.", loyalty: 10, cunning: 10, reputation: 5, survival: 0.90, response: "You become a cheerleader for Soviet space achievements. The propaganda value is enormous and genuine. Attaching yourself to unambiguous victories is the easiest form of political success."},
        {text: "Push for military applications of rocket technology — ICBMs are more important than satellites.", loyalty: 5, cunning: 5, reputation: 0, survival: 0.85, response: "You advocate prioritizing the military rocket program. The marshals appreciate your support. Khrushchev himself sees nuclear missiles as the foundation of Soviet security, so you are aligned with his thinking."},
        {text: "Argue for a balanced approach — space exploration and military applications can develop together.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You propose a dual-track approach that satisfies both the space enthusiasts and the military. This is essentially what happens — the same rockets serve both purposes. Your pragmatism is appreciated."},
        {text: "Warn that the space program is consuming too many resources that should go to consumer goods.", loyalty: -5, cunning: -5, reputation: 5, survival: 0.70, response: "You argue for butter over rockets. This is economically sensible but politically tone-deaf in the post-Sputnik euphoria. Khrushchev is not going to slow down his greatest triumph."}
      ]
    },
    {
      text: "The Seven-Year Plan replaces the traditional Five-Year Plan. Khrushchev promises to overtake America in per capita production by 1970. Chemical industry expansion is the new priority. Meanwhile, Khrushchev's educational reforms threaten the privileges of the elite — he wants all students to do manual labor before attending university. The intelligentsia is alarmed.",
      choices: [
        {text: "Support the educational reforms enthusiastically — every young person should know physical labor.", loyalty: 10, cunning: 0, reputation: -5, survival: 0.80, response: "You champion mandatory work experience before university. Party ideologues approve, but the reform quietly fails as elite families find ways to exempt their children. Your enthusiasm is wasted on a doomed policy."},
        {text: "Focus on the chemical industry targets — this is where real economic progress can be made.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.90, response: "You become an advocate for chemical industry development. Khrushchev is genuinely enthusiastic about chemistry as a path to agricultural and industrial modernization. Your expertise makes you valuable."},
        {text: "Quietly work to soften the educational reforms to protect the children of nomenklatura families.", loyalty: 0, cunning: 15, reputation: -5, survival: 0.90, response: "You create loopholes in the labor requirement. The nomenklatura is grateful. Khrushchev's reform is undermined but the elite's loyalty to you personally is strengthened. Networks matter more than policies."},
        {text: "Question whether overtaking America by 1970 is a realistic target — suggest more modest goals.", loyalty: -10, cunning: -5, reputation: 5, survival: 0.65, response: "You dare to suggest Khrushchev's targets are unrealistic. They are, of course — the USSR never comes close to American living standards. But questioning the leader's promises is never appreciated."}
      ]
    },
    {
      text: "Khrushchev makes his famous visit to the United States in 1959, touring farms and factories, meeting Hollywood stars, and being denied entry to Disneyland for security reasons. His shoe-banging incident at the UN will come later. The visit is a sensation. Back home, some hardliners grumble that the leader is clowning on the world stage. How do you respond?",
      choices: [
        {text: "Praise the visit as a diplomatic triumph — Khrushchev showed America the confidence of Soviet power.", loyalty: 10, cunning: 5, reputation: 0, survival: 0.85, response: "You celebrate the visit as a bold stroke of personal diplomacy. Khrushchev was indeed effective, and the 'Spirit of Camp David' briefly thaws US-Soviet relations. Supporting the leader's diplomacy is safe."},
        {text: "Privately agree with critics that Khrushchev's behavior was undignified for a head of state.", loyalty: -5, cunning: 0, reputation: 5, survival: 0.70, response: "You share quiet disapproval of Khrushchev's antics. The critique has merit but expressing it is dangerous. Khrushchev does not forgive those who mock his diplomatic style."},
        {text: "Focus on the practical outcomes — use the visit to push for expanded trade and cultural exchanges.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.90, response: "You extract concrete policy proposals from the visit's goodwill. Trade agreements and cultural exchanges benefit both sides. Being the person who turns spectacle into substance is always valuable."},
        {text: "Use the American trip as an opportunity to request your own foreign travel — expand your diplomatic role.", loyalty: 0, cunning: 10, reputation: 0, survival: 0.85, response: "You leverage the post-visit enthusiasm to secure your own Western travel assignments. Foreign experience is valuable both for policy expertise and for the personal benefits of Western access."}
      ]
    },
    {
      text: "The Berlin Crisis is building. Khrushchev issues an ultimatum demanding Western forces leave West Berlin within six months. The city is a hemorrhage point for East Germany — thousands flee to the West monthly through Berlin. The East German leadership begs Moscow for a solution. Khrushchev raises the stakes but is not yet ready for the Wall that will come in 1961.",
      choices: [
        {text: "Support a firm line on Berlin — Western forces must go and German reunification must be on Soviet terms.", loyalty: 10, cunning: 5, reputation: 0, survival: 0.85, response: "You back Khrushchev's aggressive Berlin diplomacy. The ultimatum is eventually quietly dropped, but the crisis establishes that the German question remains the fulcrum of the Cold War."},
        {text: "Warn against brinkmanship — a miscalculation over Berlin could trigger nuclear war.", loyalty: -5, cunning: 5, reputation: 5, survival: 0.75, response: "You counsel caution on the most dangerous flashpoint in the Cold War. The risk of nuclear escalation is real. Khrushchev is actually more cautious than his rhetoric suggests, but he dislikes having that pointed out."},
        {text: "Propose economic measures to strengthen East Germany and reduce the emigration problem.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You suggest addressing the root cause — if East Germany were more prosperous, fewer people would flee. This is sensible but the GDR's economic model cannot compete with West Germany's, regardless of Soviet subsidies."},
        {text: "Advocate for building physical barriers to stop emigration from East Berlin.", loyalty: 5, cunning: 10, reputation: -5, survival: 0.85, response: "You propose what will eventually become the Berlin Wall two years later. The idea is circulating in Moscow and East Berlin. It solves the emigration crisis at the cost of a permanent propaganda defeat."}
      ]
    },
    {
      text: "Khrushchev's agricultural obsessions intensify. After visiting Iowa, he becomes convinced that corn is the solution to Soviet agriculture. He orders corn planted everywhere — including regions where the climate is completely unsuitable. Agricultural officials who resist are dismissed. Lysenko, the fraudulent biologist, has regained influence by supporting Khrushchev's ideas.",
      choices: [
        {text: "Plant corn everywhere as ordered and report glowing results regardless of actual harvests.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.85, response: "You cover your region in corn and your reports in lies. The corn fails but your statistics show success. Khrushchev is pleased with the numbers. The Soviet agricultural reporting system becomes completely fictional."},
        {text: "Implement the corn campaign selectively — plant it where conditions allow, maintain other crops elsewhere.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You practice the art of selective compliance. Corn goes in demonstration fields near main roads; proven crops continue in the interior. Your actual production numbers remain respectable."},
        {text: "Openly challenge Lysenko's pseudoscience — real genetics must guide agricultural policy.", loyalty: -10, cunning: -10, reputation: 15, survival: 0.55, response: "You attack Lysenko's fraudulent biology. This is scientifically courageous and politically suicidal. Khrushchev personally supports Lysenko. Several geneticists who challenged him have been destroyed."},
        {text: "Propose a scientific comparison trial — grow corn and traditional crops side by side and let the results speak.", loyalty: 0, cunning: 10, reputation: 10, survival: 0.75, response: "You suggest an empirical test. In theory this should settle the matter, but Khrushchev does not want scientific comparisons — he wants corn. Your reasonableness is treated as obstruction."}
      ]
    },
    {
      text: "The cultural thaw continues unevenly. Khrushchev personally intervenes in artistic matters, alternately liberalizing and cracking down based on his mood. He praises some avant-garde art then furiously denounces abstract painting at a Moscow exhibition, calling it 'donkey art.' Writers and artists never know where the line is. You are asked to speak on cultural policy.",
      choices: [
        {text: "Echo Khrushchev's denunciation of abstract art — socialist realism remains the only legitimate form.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.85, response: "You attack modernist art with Khrushchev's own vocabulary. The cultural establishment appreciates your orthodoxy. But Khrushchev's own position shifts constantly, making cultural pronouncements risky."},
        {text: "Defend artistic experimentation — the thaw should mean creative freedom within socialist principles.", loyalty: -5, cunning: 0, reputation: 10, survival: 0.70, response: "You advocate for a broader cultural policy. Liberal intellectuals appreciate your position, but Khrushchev's anti-modernist outbursts show that the thaw has clear limits."},
        {text: "Avoid specific aesthetic judgments — focus on expanding cultural infrastructure like theaters and libraries.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You talk about building theaters rather than about what should be performed in them. Cultural infrastructure is safe ground — no one opposes more libraries. You avoid the ideological minefield entirely."},
        {text: "Propose sending more Soviet artists abroad to demonstrate the vitality of socialist culture.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You advocate cultural diplomacy — ballet tours, art exhibitions, musical performances abroad. This serves both cultural and political goals and avoids the dangerous question of domestic artistic freedom."}
      ]
    },
    {
      text: "Relations with China are deteriorating rapidly. Mao is furious about de-Stalinization and Khrushchev's pursuit of peaceful coexistence with the West. Chinese rhetoric becomes increasingly aggressive. Soviet nuclear technology transfer to China has been halted. The ideological rift between Moscow and Beijing threatens to split the world Communist movement. You must address the Chinese question.",
      choices: [
        {text: "Take a hard line against Chinese 'dogmatism' and 'adventurism' — solidarity with Khrushchev.", loyalty: 10, cunning: 5, reputation: 0, survival: 0.85, response: "You denounce Chinese positions in ideological terms. This aligns perfectly with the Soviet leadership. The Sino-Soviet split will deepen regardless, but your loyalty to Moscow's line is noted."},
        {text: "Advocate for continued dialogue — the split can still be healed if both sides compromise.", loyalty: 0, cunning: 5, reputation: 10, survival: 0.80, response: "You urge diplomacy and compromise. This is increasingly unrealistic as both Moscow and Beijing harden their positions, but your conciliatory stance offends neither side dramatically."},
        {text: "Use the Chinese threat to argue for stronger ties with Western Communist parties and the Non-Aligned Movement.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You propose compensating for the loss of China by strengthening relations elsewhere. This forward-looking diplomatic strategy serves Soviet interests regardless of the Chinese outcome."},
        {text: "Side with Chinese criticisms of peaceful coexistence — the class struggle cannot be abandoned.", loyalty: -15, cunning: -10, reputation: 0, survival: 0.50, response: "You echo Maoist rhetoric within the Soviet party. This is perceived as near-treasonous disloyalty to Khrushchev. Pro-Chinese dissidents within Soviet parties are ruthlessly marginalized."}
      ]
    }
  ],
  22: [
    {
      text: "Gagarin has orbited the Earth. The Soviet Union has achieved humanity's greatest technological triumph. Khrushchev is ecstatic and wants to leverage the achievement for maximum political effect. Gagarin becomes a global celebrity. Meanwhile, the American space program is scrambling to catch up. You are involved in decisions about how to use the space triumph politically.",
      choices: [
        {text: "Propose a global tour for Gagarin — let the world see Soviet superiority in person.", loyalty: 10, cunning: 10, reputation: 5, survival: 0.90, response: "You organize Gagarin's world tour. The cosmonaut charms audiences everywhere. The propaganda value is immense. Attaching yourself to the space program's glory is the smartest career move available."},
        {text: "Argue for keeping space technology secret — the military applications must be protected.", loyalty: 5, cunning: 5, reputation: 0, survival: 0.80, response: "You prioritize security over propaganda. The military agrees, but Khrushchev wants the publicity. The openness debate within the space program will continue for decades."},
        {text: "Push for international space cooperation — invite other nations to join Soviet space missions.", loyalty: 0, cunning: 10, reputation: 10, survival: 0.85, response: "You propose internationalist cooperation in space. This idea is ahead of its time — joint missions will eventually happen in the 1970s. For now, both superpowers prefer racing to cooperating."},
        {text: "Use the space success to demand increased funding for all Soviet science, not just rocketry.", loyalty: 5, cunning: 10, reputation: 10, survival: 0.85, response: "You try to spread the space program's prestige to all of Soviet science. More funding for laboratories, universities, and research institutes. The scientific community appreciates your advocacy."}
      ]
    },
    {
      text: "The Berlin Wall is going up in August 1961. The decision was made jointly by Moscow and the East German leadership. The Wall stops the hemorrhage of refugees but becomes a global symbol of Communist oppression. Western propaganda exploits it relentlessly. You are involved in drafting the Soviet response to international criticism.",
      choices: [
        {text: "Frame the Wall as an 'Anti-Fascist Protection Barrier' — it defends socialism from Western sabotage.", loyalty: 10, cunning: 10, reputation: -5, survival: 0.90, response: "You help craft the propaganda narrative that the Wall keeps Western saboteurs out rather than East Germans in. The line is absurd but becomes official dogma for nearly three decades."},
        {text: "Deflect attention from the Wall by highlighting Western racial inequality and colonial crimes.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You deploy the classic Soviet propaganda technique of 'whataboutism.' American segregation and European colonialism provide endless material for counter-narratives. Effective if cynical."},
        {text: "Privately acknowledge the Wall is a propaganda disaster and push for improving East German living standards.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.85, response: "You recognize the Wall's terrible optics and argue for making the Eastern bloc more attractive. This is sensible but expensive, and the GDR's structural economic problems cannot be solved with subsidies alone."},
        {text: "Express concerns that the Wall could provoke a dangerous Western military response.", loyalty: -5, cunning: 5, reputation: 5, survival: 0.75, response: "You warn about escalation. The risk was real — American and Soviet tanks faced each other at Checkpoint Charlie in October 1961. Your caution looks prudent in retrospect but was unwelcome during the crisis."}
      ]
    },
    {
      text: "The new Party Program adopted at this Congress promises the construction of communism by 1980. Free housing, free public transport, the withering away of the state — all within two decades. Everyone knows these promises are unrealistic. But the Program must be debated and adopted with enthusiasm. How do you handle this exercise in collective fantasy?",
      choices: [
        {text: "Deliver a passionate speech about the radiant communist future — free housing for all by 1980!", loyalty: 10, cunning: 0, reputation: 0, survival: 0.80, response: "You embrace the utopian vision with apparent sincerity. By 1980, under Brezhnev, the Program will be quietly forgotten. No one will remember or care about your speech."},
        {text: "Focus your remarks on the concrete, achievable goals within the Program — housing construction, education reform.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You extract the realistic elements from the utopian framework and focus on those. Housing construction, educational expansion, healthcare improvements — these are achievable and you can be held accountable for actual results."},
        {text: "Praise the Program as a theoretical masterpiece while gently noting it requires 'favorable conditions' to achieve.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You insert caveats and qualifications that provide an escape clause when the targets are missed. The language of 'favorable conditions' and 'objective circumstances' will be useful in 1980 when communism has not arrived."},
        {text: "Privately tell colleagues the whole exercise is absurd — nobody believes communism will arrive by 1980.", loyalty: -5, cunning: -5, reputation: 5, survival: 0.70, response: "You express private skepticism. Nearly everyone agrees but no one will say so publicly. Your honesty creates a bond with like-minded colleagues but also gives them leverage over you if politics shifts."}
      ]
    },
    {
      text: "The Sino-Soviet split is now public. China has openly attacked Soviet 'revisionism.' Albania has sided with Beijing. Khrushchev responds by breaking relations with Albania — a proxy war against China. The world Communist movement is fracturing. Some parties side with Moscow, others with Beijing. You represent the Soviet party at an international Communist meeting.",
      choices: [
        {text: "Attack China aggressively — Mao is a reckless adventurist leading the Chinese people to disaster.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.85, response: "You deliver a fierce anti-Chinese speech. The Moscow-aligned parties applaud. But several Asian and African parties are uncomfortable with the ferocity of the attack. Soviet influence in the Third World suffers."},
        {text: "Focus criticism on Albania as a proxy — attack Hoxha without directly naming Mao.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You follow the diplomatic convention of attacking Albania when you mean China. This allows for the possibility of future reconciliation while satisfying Moscow's need for a strong response."},
        {text: "Propose a new international conference to resolve differences — keep channels of communication open.", loyalty: 5, cunning: 10, reputation: 10, survival: 0.85, response: "You advocate for dialogue. Several international conferences will be attempted, all failing. But your diplomatic instinct earns you respect among moderate parties worldwide."},
        {text: "Argue that the split benefits the USSR — we no longer need to defer to Chinese extremism.", loyalty: 0, cunning: 10, reputation: 0, survival: 0.85, response: "You reframe the split as liberation. Without China constraining Soviet foreign policy, Moscow can pursue detente with the West more freely. This silver-lining argument has genuine strategic merit."}
      ]
    },
    {
      text: "Khrushchev's administrative reorganizations are creating chaos. He has split the party into industrial and agricultural branches, disrupting every official's power base. Regional party secretaries who used to control everything in their territory now share authority. The bureaucracy seethes with quiet resentment. Brezhnev and Suslov are collecting grievances.",
      choices: [
        {text: "Implement the reorganization loyally — Khrushchev is still the leader and his reforms must be obeyed.", loyalty: 10, cunning: 0, reputation: 0, survival: 0.75, response: "You dutifully implement the bifurcation. Your loyalty to Khrushchev is noted, but so is your association with his most hated policy. When Khrushchev falls, those who implemented the reorganization most eagerly are vulnerable."},
        {text: "Join the quiet resistance — signal to Brezhnev and Suslov that you share their frustrations.", loyalty: -5, cunning: 15, reputation: 0, survival: 0.90, response: "You align with the forces that will overthrow Khrushchev in 1964. The conspiracy is forming, and your early participation ensures you will benefit from the change of leadership. A prescient calculation."},
        {text: "Implement the reform nominally while preserving your actual authority through informal channels.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You create the appearance of compliance while maintaining real control through personal networks. The formal structure changes; the informal one does not. This is how the Soviet system always actually operates."},
        {text: "Use the reorganization to expand your own authority — grab territory from confused rivals.", loyalty: 0, cunning: 10, reputation: -5, survival: 0.85, response: "You exploit the chaos to enlarge your domain. When structures are in flux, aggressive empire-builders thrive. But the reorganization will be reversed, and your land grabs may be reversed with it."}
      ]
    },
    {
      text: "Stalin's body has been removed from Lenin's Mausoleum and reburied in a simple grave by the Kremlin wall. Stalingrad is renamed Volgograd. The Congress passes resolutions condemning the cult of personality. But some delegates — especially military veterans and older party members — are uncomfortable. They feel their life's work under Stalin is being delegitimized.",
      choices: [
        {text: "Support the full removal of Stalin's legacy — rename every city and institution bearing his name.", loyalty: 10, cunning: 0, reputation: 5, survival: 0.80, response: "You push for thorough de-Stalinization. Khrushchev appreciates your zeal, but the backlash among veterans and conservatives builds. Every renamed street creates resentment that will fuel the eventual reaction."},
        {text: "Advocate for a nuanced approach — condemn Stalin's crimes while preserving respect for wartime achievements.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You propose a selective de-Stalinization that condemns the Terror while honoring the war victory. This balanced position will essentially become the final Soviet consensus on Stalin — maintained through to the end."},
        {text: "Express sympathy for veterans who feel their sacrifices under Stalin are being dishonored.", loyalty: -5, cunning: 5, reputation: 10, survival: 0.75, response: "You voice the feelings of millions who served under Stalin and now feel their lives were lived in vain. This is emotionally resonant but politically out of step with Khrushchev's direction."},
        {text: "Redirect the conversation to future achievements — the space program, the new Party Program, the promise of communism.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You pivot from the painful past to the shining future. This optimistic framing serves the leadership's interests and spares you from taking a position on the most divisive question of the era."}
      ]
    },
    {
      text: "The Cuban Missile Crisis is months away, though no one at the Congress knows it yet. Khrushchev is already contemplating placing nuclear missiles in Cuba to address the strategic imbalance — the US has missiles in Turkey and Italy aimed at the USSR. Soviet generals are divided. Some see it as a brilliant gambit; others as reckless provocation. Preliminary discussions begin.",
      choices: [
        {text: "Support placing missiles in Cuba — it corrects the strategic imbalance at a stroke.", loyalty: 10, cunning: 5, reputation: 0, survival: 0.80, response: "You back Khrushchev's plan. The crisis will nearly destroy the world in October 1962 before a last-minute settlement. Those who supported the deployment will bear responsibility for the most dangerous moment in human history."},
        {text: "Warn that placing missiles near America could trigger an uncontrollable escalation.", loyalty: -5, cunning: 10, reputation: 5, survival: 0.80, response: "You counsel caution. Events will prove you right — the crisis brings the world to the brink. But Khrushchev does not appreciate having his bold plans questioned, even when the questioners are correct."},
        {text: "Propose alternative means of defending Cuba — conventional arms, Soviet naval presence, economic aid.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.85, response: "You suggest defending Cuba without nuclear missiles. These alternatives are less dramatic but also less dangerous. Your measured approach does not match Khrushchev's appetite for the grand gesture."},
        {text: "Support whatever the General Secretary decides — this is above your pay grade.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You defer to the leadership on nuclear strategy. Not every battle is yours to fight. Sometimes the wisest move is recognizing when a decision belongs to others and keeping your head down."}
      ]
    },
    {
      text: "Khrushchev demands that all Congress delegates endorse a letter to the Chinese Communist Party criticizing their positions. The letter is harsh, accusing China of splitting the world Communist movement. Some delegates from non-Russian republics have ethnic or cultural ties to Central Asian peoples across the Chinese border. The letter will damage those relationships.",
      choices: [
        {text: "Sign enthusiastically and add personal criticisms of Chinese policy.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.85, response: "You exceed the minimum requirement, adding your own denunciations. Khrushchev appreciates the enthusiasm. The letter further poisons Sino-Soviet relations, contributing to the border clashes that will come in 1969."},
        {text: "Sign the letter as required but work behind the scenes to soften its language.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You comply with the directive while trying to moderate the tone. Some of your suggested amendments are incorporated. The letter is still harsh, but marginally less inflammatory than it might have been."},
        {text: "Request that the letter acknowledge the positive aspects of past Sino-Soviet cooperation.", loyalty: 0, cunning: 5, reputation: 5, survival: 0.80, response: "You push for balance in the letter. This reasonable suggestion is partially adopted but the overall thrust remains combative. Your effort to maintain diplomatic bridges is noted by the foreign affairs establishment."},
        {text: "Raise concerns about the impact on Soviet Central Asian populations with cross-border ties to China.", loyalty: -5, cunning: 5, reputation: 5, survival: 0.75, response: "You advocate for your constituents' interests. The nationalities dimension of the Sino-Soviet split is real but the leadership does not want complications. Your concerns are acknowledged but ignored."}
      ]
    }
  ],
  23: [
    {
      text: "Khrushchev has been overthrown. The conspirators — Brezhnev, Suslov, Shelest, Shelepin, and others — acted while he was on vacation in Crimea. He was summoned back to Moscow and confronted with a list of grievances. Unlike in previous Soviet power struggles, Khrushchev is simply retired on pension. You must now seamlessly transfer your loyalty to the new collective leadership.",
      choices: [
        {text: "Immediately and vocally denounce Khrushchev's 'harebrained schemes' and 'voluntarism.'", loyalty: 10, cunning: 5, reputation: -5, survival: 0.90, response: "You attack the fallen leader with gusto. The new leadership approves, but some colleagues note how quickly you switched allegiance. Your flexibility is an asset that also undermines trust."},
        {text: "Express measured support for the new leadership without personally attacking Khrushchev.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.95, response: "You welcome the new collective leadership while avoiding personal attacks on Khrushchev. This dignified transition shows political maturity. Brezhnev himself prefers a quiet removal of Khrushchev's legacy to a noisy denunciation."},
        {text: "Speak in defense of some of Khrushchev's achievements — the space program, de-Stalinization, the Thaw.", loyalty: -10, cunning: -10, reputation: 10, survival: 0.55, response: "You defend the fallen leader. This is politically disastrous — the entire leadership has united around his removal. Your loyalty to a powerless pensioner earns you nothing but suspicion."},
        {text: "Focus on calling for the reversal of Khrushchev's party reorganization — restore the unified party structure.", loyalty: 10, cunning: 10, reputation: 5, survival: 0.95, response: "You attack Khrushchev's most unpopular policy rather than the man himself. The party apparatus rejoices at the reunification of the industrial and agricultural branches. You are rewarded for addressing their top grievance."}
      ]
    },
    {
      text: "Kosygin is implementing economic reforms — limited enterprise autonomy, profit incentives, quality bonuses. The reforms mirror some ideas from the economist Liberman. Conservative ideologues see market elements creeping into the planned economy. Brezhnev is ambivalent — he likes stability, not experiments. The Prague Spring in two years will kill these reforms dead.",
      choices: [
        {text: "Support Kosygin's reforms — the economy needs modernization and flexibility.", loyalty: 0, cunning: 5, reputation: 10, survival: 0.80, response: "You back the reforms intellectually. Kosygin appreciates the support, but his influence is already waning relative to Brezhnev. The reforms are implemented halfheartedly and gradually abandoned."},
        {text: "Express ideological concerns about profit incentives — this smells of capitalism.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.85, response: "You voice conservative objections. After the Prague Spring, when Czechoslovak economic reforms are linked to political liberalization, your ideological caution will look prescient to the party apparatus."},
        {text: "Support the reforms in your sector while maintaining traditional planning elsewhere — hedge your bets.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You implement reforms selectively, showing results where possible while maintaining control where reforms might be reversed. When the reforms are eventually strangled, you have not overcommitted."},
        {text: "Propose your own reform ideas building on Kosygin's framework — take intellectual ownership.", loyalty: 0, cunning: 10, reputation: 10, survival: 0.80, response: "You develop and publish your own reform proposals. This establishes you as a serious economic thinker. The reforms may fail politically, but your intellectual reputation grows."}
      ]
    },
    {
      text: "The Sinyavsky-Daniel trial has shocked the intelligentsia. Two writers — Andrei Sinyavsky and Yuli Daniel — have been imprisoned for publishing satirical works abroad under pseudonyms. For the first time since Stalin, writers are being jailed for their words. A petition signed by sixty-three prominent intellectuals protests the sentences. How do you respond to this cultural crisis?",
      choices: [
        {text: "Support the sentences — publishing abroad under false names is anti-Soviet activity.", loyalty: 10, cunning: 5, reputation: -10, survival: 0.90, response: "You endorse the crackdown. The security services are satisfied. The trial becomes a watershed — it launches the dissident movement by proving that even the post-Stalin system will jail writers."},
        {text: "Argue the trial was a mistake — it created more dissent than it suppressed.", loyalty: -5, cunning: 10, reputation: 10, survival: 0.75, response: "You make the pragmatic case that the trial backfired. Western media coverage made Sinyavsky and Daniel into martyrs. Some in the leadership privately agree, but the sentence cannot be reversed without losing face."},
        {text: "Propose a more sophisticated cultural policy — co-opt rather than confront the intelligentsia.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You advocate for managed tolerance rather than crude repression. Let writers publish within broader limits, provide privileged access to dachas and foreign travel, and reserve punishment for the truly dangerous."},
        {text: "Ignore the trial entirely and focus your energy on technical and economic questions.", loyalty: 0, cunning: 10, reputation: 0, survival: 0.85, response: "You refuse to engage with cultural politics. In the Brezhnev era, boring competence in mundane areas is the safest path. Let others fight about writers while you manage industry."}
      ]
    },
    {
      text: "A power struggle is developing between Brezhnev and Shelepin, the former KGB chief and Young Communist League leader. Shelepin represents a younger, more dynamic faction that some fear could become a Soviet Kennedy. Brezhnev is methodically isolating him. You must navigate between these factions without being destroyed by either.",
      choices: [
        {text: "Align with Brezhnev — he controls the party apparatus and plays the long game.", loyalty: 10, cunning: 15, reputation: 0, survival: 0.95, response: "You back the eventual winner. Brezhnev slowly strips Shelepin of his positions over the next several years. Your early commitment to Brezhnev marks you as a reliable member of his network."},
        {text: "Support Shelepin's calls for more dynamic leadership and anti-corruption measures.", loyalty: -10, cunning: -5, reputation: 10, survival: 0.60, response: "You back the losing horse. Shelepin is talented but outmaneuvered. As his allies are removed from key positions, your association with him becomes a liability."},
        {text: "Maintain strict neutrality — serve the collective leadership without favoring any individual.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.85, response: "You play both sides carefully. When the dust settles, Brezhnev notes that you were not against him — though he also notes you were not for him. Neutrality earns survival but not advancement."},
        {text: "Focus on building your own independent power base rather than attaching to either leader.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.85, response: "You invest in your own network rather than depending on a patron. In the 'stability of cadres' era, regional and institutional power bases become semi-permanent. Independence has value."}
      ]
    },
    {
      text: "Vietnam is escalating. The United States is pouring troops into South Vietnam while the USSR supplies North Vietnam with weapons and advisors. Cuba, Prague, Hanoi — the global Cold War is intensifying. The military-industrial complex demands more resources. Brezhnev sees an opportunity to gain influence in the Third World. Your input is requested on the level of Soviet support for Vietnam.",
      choices: [
        {text: "Advocate maximum support for North Vietnam — provide the latest air defense systems and military advisors.", loyalty: 10, cunning: 5, reputation: 5, survival: 0.90, response: "You push for aggressive support. Soviet SAMs and MiGs prove devastatingly effective against American aircraft. The Vietnam War becomes America's quagmire, and Soviet military prestige soars."},
        {text: "Support Vietnam but counsel against direct Soviet-American confrontation — no Soviet combat troops.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.95, response: "You advocate the approach that is actually adopted: maximum material support with minimum direct involvement. Soviet 'advisors' serve in Vietnam but officially the USSR is not at war with America."},
        {text: "Argue that the resources spent in Vietnam would be better invested in the Soviet economy.", loyalty: -5, cunning: 5, reputation: 5, survival: 0.75, response: "You question the cost of Third World commitments. This is economically rational but ideologically unacceptable — support for national liberation movements is a core Soviet commitment."},
        {text: "Propose using Vietnam as leverage in arms control negotiations with America.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.90, response: "You see Vietnam as a diplomatic card to play. This is exactly what happens — the Vietnam War and detente negotiations proceed in parallel, each influencing the other. Your strategic thinking is appreciated."}
      ]
    },
    {
      text: "The question of Stalin's legacy returns. Under Brezhnev, a quiet rehabilitation is underway — not restoring the cult of personality, but ending the public criticism. Stalin's name disappears from official denunciations. His wartime leadership is cautiously praised. The city of Volgograd remains renamed, but the tone has shifted. How do you calibrate your position on Stalin?",
      choices: [
        {text: "Support the quiet rehabilitation — Stalin's wartime achievements deserve recognition.", loyalty: 10, cunning: 10, reputation: 0, survival: 0.90, response: "You align with Brezhnev's calibrated approach: honor the victory in the Great Patriotic War without reviving the cult of personality. This is exactly the tightrope the leadership wants to walk."},
        {text: "Warn against any rehabilitation — the crimes of the Terror must never be forgotten.", loyalty: -5, cunning: -5, reputation: 10, survival: 0.70, response: "You argue for maintaining the spirit of the 20th Congress. But the political winds have shifted. Under Brezhnev, insisting on anti-Stalinist positions marks you as a Khrushchevite holdover."},
        {text: "Adopt whatever position your immediate superior holds — let the bosses lead on this sensitive topic.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.95, response: "You mirror your patron's position exactly. On a question this politically charged, following the local hierarchy is the safest approach. Independent positions on Stalin are always dangerous."},
        {text: "Propose a scholarly commission to produce an authoritative assessment of the Stalin period.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.80, response: "You try to depoliticize the question by handing it to academics. The leadership has no interest in a definitive accounting — ambiguity on Stalin serves their purposes better than clarity."}
      ]
    },
    {
      text: "Brezhnev wants the Congress to formalize the principle of 'collective leadership' while he quietly accumulates personal power. The Congress also discusses the new five-year plan. Economic growth is still positive but decelerating. Consumer goods remain scarce compared to the West. You have access to comparative economic data showing the growing gap.",
      choices: [
        {text: "Present optimistic production figures and praise the superiority of the planned economy.", loyalty: 10, cunning: 5, reputation: 0, survival: 0.90, response: "You deliver the expected speech full of impressive-sounding but carefully selected statistics. The economy is not actually collapsing — growth continues, just more slowly. Your optimism is not entirely dishonest."},
        {text: "Share concerning comparative data in closed Politburo sessions while maintaining public optimism.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You practice the dual discourse that defines Soviet governance — truth in private, fiction in public. The leadership appreciates your honesty behind closed doors and your discretion in public."},
        {text: "Argue publicly that the economy requires structural reform to maintain competitiveness.", loyalty: -10, cunning: -5, reputation: 10, survival: 0.60, response: "You raise the alarm publicly. The Brezhnev era does not reward economic prophets. The system's response to structural problems is to suppress the data rather than fix the problems."},
        {text: "Focus on specific achievable improvements in your sector rather than system-wide critique.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.90, response: "You propose targeted improvements within your area of responsibility. Incremental progress within the existing system is the most that can be achieved. Your practical focus serves you well."}
      ]
    },
    {
      text: "The Prague Spring is approaching. In Czechoslovakia, reformers led by Dubcek are discussing 'socialism with a human face' — economic reforms, press freedom, and political liberalization. Soviet intelligence reports reach the Politburo. The parallel to Hungary 1956 is obvious. But Czechoslovakia is strategically vital — it sits in the center of the Warsaw Pact's defensive line.",
      choices: [
        {text: "Warn that Czechoslovak reforms will spread contagion — intervene before it is too late.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.85, response: "You advocate early intervention. The Warsaw Pact will eventually invade in August 1968. Your hawkish position is vindicated by events, at least from the perspective of the Soviet leadership."},
        {text: "Counsel patience — let the Czechoslovaks experiment within limits, as Poland did in 1956.", loyalty: -5, cunning: 5, reputation: 10, survival: 0.70, response: "You argue for a softer approach. But unlike 1956 Poland, the Czechoslovak reforms go further and faster. When invasion comes, your counsel of patience looks naive."},
        {text: "Propose economic pressure rather than military intervention — cut subsidies and trade.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.80, response: "You suggest economic leverage as an alternative to tanks. This approach is tried but proves insufficient — the reforms continue. Eventually the leadership concludes that only military force will work."},
        {text: "Stay silent on Czechoslovakia and focus exclusively on domestic Soviet issues.", loyalty: 0, cunning: 10, reputation: 0, survival: 0.85, response: "You avoid the Czechoslovak question entirely. It is the most consequential foreign policy decision since Hungary, but sometimes the safest position is having no position on the most dangerous question."}
      ]
    }
  ],
  24: [
    {
      text: "The Prague Spring has been crushed by Warsaw Pact tanks. The 'Brezhnev Doctrine' — declaring the right to intervene in any socialist state — is the new reality. But the invasion has damaged Soviet prestige worldwide. Western Communist parties — especially the Italian and French — are outraged. You are sent to explain the intervention to a meeting of European Communist leaders.",
      choices: [
        {text: "Defend the invasion firmly — Czechoslovakia was about to leave the socialist camp and NATO was waiting.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.90, response: "You present the hard line. Most Eastern European parties dutifully agree. The Italian and French parties are appalled. The invasion accelerates the development of 'Eurocommunism' — independent Western Communist parties that reject Soviet authority."},
        {text: "Acknowledge that the intervention was painful but necessary — express regret while defending the decision.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You strike a tone of reluctant necessity. This resonates better than crude triumphalism. Some Western party leaders accept the argument even while disagreeing. Your diplomatic touch is noted."},
        {text: "Deflect blame onto the Czechoslovak reformers — they provoked the intervention by going too far.", loyalty: 10, cunning: 10, reputation: -5, survival: 0.85, response: "You blame the victims. Dubcek and the Prague Spring reformers are portrayed as naive idealists who opened the door to counter-revolution. This is the standard Soviet narrative and it serves you adequately."},
        {text: "Privately sympathize with Western party leaders' objections while publicly maintaining the official line.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.80, response: "You play a double game — orthodox in the formal sessions, understanding in the corridors. This builds personal relationships with foreign leaders while protecting your position at home. A diplomat's approach."}
      ]
    },
    {
      text: "Detente is advancing. The SALT I negotiations aim to limit strategic nuclear weapons. Brezhnev sees arms control as his signature achievement — a way to stabilize the Cold War and reduce the crippling burden of military spending. The military wants to negotiate from strength. Hard-liners within the Politburo are suspicious of American intentions.",
      choices: [
        {text: "Champion SALT negotiations enthusiastically — arms control benefits Soviet security and the economy.", loyalty: 10, cunning: 10, reputation: 5, survival: 0.90, response: "You become an advocate for detente. Brezhnev appreciates the support. The SALT I treaty is signed in 1972, capping strategic missiles. Arms control becomes a cornerstone of Soviet foreign policy."},
        {text: "Support negotiations but push for maintaining Soviet military advantages in specific areas.", loyalty: 5, cunning: 10, reputation: 0, survival: 0.90, response: "You back arms control while protecting Soviet weapons programs that fall outside the treaty's scope. This balanced position satisfies both the diplomats and the generals."},
        {text: "Warn that arms control creates dangerous complacency — America cannot be trusted.", loyalty: 0, cunning: 5, reputation: 0, survival: 0.85, response: "You voice hardline skepticism. The military-industrial complex agrees, but Brezhnev has committed himself to detente. Opposition to his signature policy is risky, though less dangerous than in previous eras."},
        {text: "Focus on the economic benefits of reduced military spending — redirect resources to consumer goods.", loyalty: 5, cunning: 5, reputation: 10, survival: 0.85, response: "You make the economic case for arms control. In reality, Soviet military spending continues to climb despite SALT. The 'peace dividend' never materializes, but your argument is appealing in theory."}
      ]
    },
    {
      text: "Solzhenitsyn's works are circulating throughout the Soviet Union and the world. 'The Gulag Archipelago' will soon be published abroad, devastating the Soviet Union's international reputation. The KGB wants him arrested; the Foreign Ministry warns this would be a propaganda disaster. Brezhnev must decide what to do with the most famous dissident in the world.",
      choices: [
        {text: "Advocate expelling Solzhenitsyn from the USSR — rid ourselves of the problem without creating a martyr in prison.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You propose the solution that is eventually adopted — forced exile in 1974. Expulsion removes the domestic problem while appearing more humane than imprisonment. A pragmatic approach to an impossible situation."},
        {text: "Demand Solzhenitsyn's arrest and trial — the state must not appear weak before its enemies.", loyalty: 10, cunning: 0, reputation: -10, survival: 0.80, response: "You call for harsh measures. The KGB agrees, but the leadership ultimately decides that a trial would give Solzhenitsyn a global platform. Your hardline stance overshoots the leadership's actual policy."},
        {text: "Propose ignoring Solzhenitsyn — denying him the attention he craves.", loyalty: 0, cunning: 5, reputation: 5, survival: 0.80, response: "You suggest starving the dissident of publicity. In the age of Western media interest, this is impossible. Solzhenitsyn will get attention regardless of Soviet policy. Your proposal is impractical."},
        {text: "Argue for addressing the substance of Solzhenitsyn's accusations — acknowledge the Gulag's reality.", loyalty: -15, cunning: -10, reputation: 15, survival: 0.50, response: "You suggest that the best response to Solzhenitsyn is truth. This is politically unthinkable — acknowledging the full scope of the Gulag would undermine the regime's legitimacy. Your suggestion is treated as borderline disloyal."}
      ]
    },
    {
      text: "The Jewish emigration question is becoming a major diplomatic issue. Thousands of Soviet Jews want to emigrate to Israel. The Jackson-Vanik Amendment in the US Congress threatens to link Soviet trade privileges to emigration policy. Brezhnev resents foreign interference in internal affairs. Arab allies are furious about any emigration to Israel.",
      choices: [
        {text: "Oppose emigration firmly — allowing Jews to leave sets a precedent for other nationalities.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.85, response: "You take the hard line. If Jews can leave, why not Germans, Armenians, Greeks? The precedent is indeed dangerous for a multinational empire. But blocking emigration damages detente."},
        {text: "Allow quiet emigration in small numbers — satisfy the Americans without making it a public issue.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You propose managed, quiet emigration. This is close to the actual policy adopted — variable numbers allowed to leave depending on the diplomatic climate. Pragmatism on a sensitive issue."},
        {text: "Use the emigration issue as a bargaining chip with America — trade exit visas for trade concessions.", loyalty: 5, cunning: 10, reputation: -5, survival: 0.85, response: "You treat human beings as diplomatic currency. Cynical but effective — Jewish emigration numbers indeed fluctuate with the state of US-Soviet relations. Linkage diplomacy at its most transactional."},
        {text: "Argue that the desire to emigrate reflects real problems — anti-Semitism and lack of cultural autonomy — that should be addressed.", loyalty: -10, cunning: -5, reputation: 15, survival: 0.55, response: "You suggest addressing root causes. This honest assessment of Soviet nationality policy is unwelcome. The leadership prefers to treat emigration as a foreign policy issue, not a domestic failure."}
      ]
    },
    {
      text: "Brezhnev's personality cult grows steadily. He awards himself the Order of Victory — a military decoration previously reserved for WWII commanders. His ghostwritten memoirs are published to universal acclaim. Every institution competes to flatter him more extravagantly. Unlike Stalin's cult, this one is more absurd than terrifying. But participation is still mandatory.",
      choices: [
        {text: "Compose the most extravagant tribute speech at the Congress — praise Brezhnev's wisdom, courage, and literary genius.", loyalty: 15, cunning: 5, reputation: -10, survival: 0.95, response: "You deliver a masterpiece of sycophancy. Brezhnev beams. Everyone applauds. The speech is indistinguishable from dozens of others. In the Brezhnev era, competitive flattery replaces competitive achievement."},
        {text: "Praise Brezhnev warmly but with a note of dignity — avoid the most ridiculous excesses.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.90, response: "You find the sweet spot between insufficient and excessive flattery. Your speech is respectful without being absurd. In an era of competitive sycophancy, restraint paradoxically stands out."},
        {text: "Redirect your speech from personal praise to institutional achievements — the party, the state, the people.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.85, response: "You praise the system rather than the man. This is noticed but not punished. Brezhnev's cult is not enforced with Stalinist ferocity — the consequences of insufficient flattery are career stagnation, not arrest."},
        {text: "Privately joke about the cult with trusted colleagues — everyone knows it is absurd.", loyalty: -5, cunning: 0, reputation: 5, survival: 0.80, response: "You share the widespread cynicism about Brezhnev's self-aggrandizement. Political jokes are the USSR's true national art form. But even in the relatively mild Brezhnev era, being known as a mocker can damage your career."}
      ]
    },
    {
      text: "Ostpolitik — West German Chancellor Brandt's policy of engagement with Eastern Europe — is transforming European politics. Moscow welcomes the treaties recognizing postwar borders but fears that increased contact with the West could undermine Eastern bloc stability. East Germany's Honecker is particularly nervous. The Conference on Security and Cooperation in Europe is being negotiated.",
      choices: [
        {text: "Support Ostpolitik enthusiastically — Western recognition of postwar borders is a historic Soviet victory.", loyalty: 10, cunning: 10, reputation: 5, survival: 0.90, response: "You champion the diplomatic process. The Helsinki Final Act will indeed recognize European borders — a massive Soviet foreign policy win. Your support for detente diplomacy is well-placed."},
        {text: "Warn about the ideological dangers of increased Western contact with Eastern Europe.", loyalty: 5, cunning: 5, reputation: 0, survival: 0.85, response: "You raise concerns about Western influence penetrating the Eastern bloc. These concerns will prove justified — the Helsinki Accords' human rights provisions become a tool for dissidents. But for now, the leadership wants the diplomatic gains."},
        {text: "Focus on extracting maximum economic concessions from West Germany in exchange for political normalization.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You turn diplomacy into commerce. West German credits, technology transfers, and trade agreements flow from Ostpolitik. The economic benefits of engagement are real and substantial."},
        {text: "Advocate for a common European security framework that could eventually replace both NATO and the Warsaw Pact.", loyalty: 0, cunning: 5, reputation: 10, survival: 0.80, response: "You propose a visionary restructuring of European security. The idea is decades ahead of its time. Neither superpower is ready to dissolve its alliance system, but your thinking marks you as a strategic thinker."}
      ]
    },
    {
      text: "The Ninth Five-Year Plan emphasizes consumer goods production — Brezhnev has promised to improve Soviet living standards. But military spending continues to consume an enormous share of the budget. The tension between guns and butter is the central dilemma of the Soviet economy. Gosplan presents competing budget proposals.",
      choices: [
        {text: "Advocate for the military — the arms race cannot be lost, consumer goods can wait.", loyalty: 5, cunning: 5, reputation: 0, survival: 0.85, response: "You back the defense establishment. Military spending continues to grow, eventually consuming an estimated 15-25% of GDP. The consumer sector stagnates, breeding public cynicism."},
        {text: "Push for consumer goods — improving living standards is essential for regime legitimacy.", loyalty: 5, cunning: 5, reputation: 10, survival: 0.85, response: "You advocate for ordinary people's needs. Brezhnev has made promises about living standards and cannot entirely ignore them. Some consumer improvements do occur — more apartments, more cars, better food supply."},
        {text: "Propose efficiency reforms that could yield more output from existing resources.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.90, response: "You suggest getting more from less. The idea is appealing but execution fails — the planned economy's incentive structure actively discourages efficiency. Your proposals look good on paper and die in practice."},
        {text: "Argue for redirecting some military-industrial capacity to civilian production — dual-use factories.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.80, response: "You propose conversion of military factories to civilian production. The military-industrial complex fights this fiercely. Conversion will remain a contested issue through perestroika and beyond."}
      ]
    },
    {
      text: "Andropov, as KGB chairman, presents a classified briefing on the dissident movement. Sakharov's Committee for Human Rights, the Chronicle of Current Events samizdat journal, and growing religious dissent among Baptists, Jews, and Ukrainian Catholics all concern the security services. Andropov argues for a sophisticated strategy combining repression with co-optation.",
      choices: [
        {text: "Support Andropov's approach — targeted repression of leaders combined with surveillance of sympathizers.", loyalty: 10, cunning: 10, reputation: -5, survival: 0.90, response: "You back the KGB chief's strategy. Andropov's methods are effective — the dissident movement never grows beyond a few hundred active participants. Your support builds a valuable alliance with the future General Secretary."},
        {text: "Argue for harsher measures — the dissidents should be crushed completely, not managed.", loyalty: 10, cunning: 0, reputation: -10, survival: 0.80, response: "You push for maximum repression. This is cruder than Andropov prefers. Mass repression would be counterproductive — it would generate more sympathy for the dissidents and damage detente."},
        {text: "Suggest addressing some of the dissidents' legitimate grievances to undercut their support.", loyalty: -5, cunning: 10, reputation: 10, survival: 0.75, response: "You argue for reform as the best weapon against dissent. Address religious freedom, emigration rights, and legal protections to remove the dissidents' constituency. This is too liberal for the Politburo."},
        {text: "Downplay the dissident threat — a few hundred intellectuals cannot endanger a superpower.", loyalty: 0, cunning: 5, reputation: 5, survival: 0.85, response: "You argue that the KGB is overstating the danger. The dissidents are indeed a tiny group. But Andropov sees threats that others miss — and he will eventually be proved right about the system's fragility."}
      ]
    }
  ],
  25: [
    {
      text: "The Helsinki Final Act has been signed in 1975. The Soviets celebrate the recognition of European borders. But Basket III — human rights provisions — has given dissidents a powerful new tool. Helsinki Watch Groups spring up in Moscow, Kyiv, Tbilisi, and Vilnius, documenting human rights violations. The KGB wants to crush them. The Foreign Ministry warns that cracking down will damage detente.",
      choices: [
        {text: "Support suppression of the Helsinki groups — they are Western tools for undermining the Soviet system.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.90, response: "You advocate crushing the Helsinki monitors. Most are eventually arrested or exiled. But the human rights framework they established proves indestructible — it will become the language of revolution in 1989."},
        {text: "Argue for tolerating the groups — their arrest would prove their accusations about human rights abuses.", loyalty: -5, cunning: 10, reputation: 10, survival: 0.75, response: "You make the paradox argument: repressing human rights monitors proves the monitors right. This logic is sound but the security establishment operates on different principles. Toleration of dissent looks like weakness."},
        {text: "Propose discrediting the groups by planting KGB agents within them.", loyalty: 10, cunning: 15, reputation: -5, survival: 0.90, response: "You suggest infiltration rather than suppression. The KGB is already doing this. Your proposal shows sophisticated understanding of security operations and aligns with Andropov's preferred methods."},
        {text: "Blame the Foreign Ministry for agreeing to Basket III — the human rights provisions were a trap.", loyalty: 5, cunning: 5, reputation: 0, survival: 0.80, response: "You attack the diplomats who negotiated Helsinki. The criticism has merit — Soviet negotiators underestimated the impact of the human rights provisions. But attacking colleagues creates enemies."}
      ]
    },
    {
      text: "Soviet influence is expanding in the Third World. Cuba has sent troops to Angola to support the MPLA government. Soviet advisors are active in Mozambique, Ethiopia, and South Yemen. The military sees opportunities; economists see costs. Brezhnev frames these interventions as the 'correlation of forces' shifting in socialism's favor globally.",
      choices: [
        {text: "Enthusiastically support Third World expansion — the global correlation of forces favors socialism.", loyalty: 10, cunning: 5, reputation: 0, survival: 0.90, response: "You embrace the expansionist narrative. Soviet influence is indeed at its Cold War peak. But the costs of maintaining client states in Africa and Asia will prove unsustainable."},
        {text: "Counsel selectivity — support only those Third World movements with genuine popular backing.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.85, response: "You argue for strategic discipline in choosing allies. Not every revolutionary movement in Africa deserves Soviet support. Some will collapse regardless of how many rubles Moscow provides."},
        {text: "Warn that Third World commitments are overextending Soviet resources — we cannot afford a global empire.", loyalty: -5, cunning: 5, reputation: 10, survival: 0.70, response: "You sound the alarm about imperial overstretch. The economic burden of supporting Cuba, Vietnam, Angola, Ethiopia, and dozens of other clients is enormous. But challenging the global strategy challenges Brezhnev's legacy."},
        {text: "Focus on using Third World allies to secure natural resources — cobalt, chromium, oil — for the Soviet economy.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You propose extracting economic value from political influence. Mineral wealth in Southern Africa and energy resources in the Middle East are strategically vital. Your pragmatic approach impresses the economic planners."}
      ]
    },
    {
      text: "Brezhnev's health is visibly declining. He slurs his speeches, shuffles when he walks, and sometimes loses his place reading prepared texts. The gerontocracy governs by inertia. Younger officials wait impatiently for advancement that only comes when someone above them dies. Succession is the unspoken obsession of the entire political class.",
      choices: [
        {text: "Remain ostentatiously loyal to Brezhnev — never acknowledge his declining health.", loyalty: 15, cunning: 5, reputation: -5, survival: 0.85, response: "You maintain the fiction of a vigorous leader. Everyone does. The elaborate pretense that Brezhnev is functioning normally becomes the defining absurdity of the era. Loyalty to a dying leader is expected but not rewarded after he dies."},
        {text: "Quietly build relationships with potential successors — Andropov, Chernenko, Gorbachev.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.90, response: "You cultivate the next generation without abandoning the current one. Andropov will succeed Brezhnev, then Chernenko, then Gorbachev. Positioning for all three is challenging but those who manage it survive the transition."},
        {text: "Use the power vacuum created by Brezhnev's incapacity to expand your own authority.", loyalty: 0, cunning: 10, reputation: -5, survival: 0.85, response: "You exploit the leadership's paralysis to quietly expand your domain. As Brezhnev becomes less able to govern, subordinates accumulate more autonomy. Bureaucratic empire-building fills the vacuum of leadership."},
        {text: "Propose institutional reforms that would ensure a smooth succession — a formal mechanism for transferring power.", loyalty: -5, cunning: 0, reputation: 10, survival: 0.70, response: "You raise the taboo topic of succession planning. The Soviet system has no formal mechanism for orderly leadership transition. Your proposal is logical but threatening — it acknowledges that the leader will die."}
      ]
    },
    {
      text: "Oil prices have quadrupled since 1973. The Soviet Union, as a major oil exporter, is awash in petrodollars. Hard currency earnings mask the economy's structural decline. The windfall allows the leadership to import Western grain and technology rather than reforming. You sit on the economic planning committee that allocates these unexpected revenues.",
      choices: [
        {text: "Invest oil revenues in modernizing Soviet industry — this windfall is a once-in-a-generation opportunity.", loyalty: 0, cunning: 10, reputation: 10, survival: 0.80, response: "You advocate using oil wealth for structural reform. This is the correct advice — and it is ignored. The revenues are spent on imports, military equipment, and subsidies to client states. The opportunity is squandered."},
        {text: "Use the money to improve consumer goods supply — keep the population satisfied.", loyalty: 10, cunning: 10, reputation: 5, survival: 0.90, response: "You argue for spending the windfall on the people's living standards. Some of this happens — the Brezhnev era sees real improvements in diet, housing, and consumer durables. But the underlying economy remains unreformed."},
        {text: "Recommend building strategic reserves — oil prices will not remain high forever.", loyalty: 0, cunning: 15, reputation: 5, survival: 0.85, response: "You counsel saving for the future. When oil prices drop in the 1980s, the Soviet economy will face a devastating revenue crisis. Your advice is prescient but unheeded — the system demands spending now."},
        {text: "Channel the revenues toward military modernization — the arms race must be won.", loyalty: 5, cunning: 5, reputation: 0, survival: 0.85, response: "You direct oil money toward new weapons systems. The military-industrial complex is the most powerful lobby in the Soviet system. Feeding it keeps powerful allies satisfied."}
      ]
    },
    {
      text: "The dissident movement gains international visibility. Sakharov wins the Nobel Peace Prize in 1975. Bukovsky is exchanged for a Chilean political prisoner. Solzhenitsyn broadcasts from exile. Western radio stations — Voice of America, Radio Liberty, BBC — beam dissident writings back into the Soviet Union. The information blockade is crumbling at the edges.",
      choices: [
        {text: "Intensify radio jamming and tighten control over Western publications entering the country.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.90, response: "You support the information blockade. Jamming is expensive and imperfect — determined listeners can still tune in. But the effort demonstrates the regime's commitment to information control."},
        {text: "Propose improving Soviet media to compete with Western broadcasts rather than just jamming them.", loyalty: 5, cunning: 10, reputation: 10, survival: 0.85, response: "You suggest making Soviet media more interesting and credible. This is a radical idea for a system built on propaganda. Some modest improvements to Soviet journalism are attempted but the structural dishonesty of the system limits progress."},
        {text: "Argue that the dissidents are irrelevant — ordinary Soviet citizens care about apartments and sausage, not human rights.", loyalty: 5, cunning: 10, reputation: 0, survival: 0.85, response: "You dismiss the significance of the dissident movement. In one sense you are right — the mass Soviet population is not reading samizdat. But the dissidents articulate a moral critique that will ultimately prove devastating."},
        {text: "Suggest selective engagement — invite some moderate critics into official dialogue to neutralize them.", loyalty: 0, cunning: 15, reputation: 5, survival: 0.85, response: "You propose co-opting rather than confronting moderate dissent. Allow limited criticism within official channels to defuse pressure. This sophisticated approach is practiced to some degree but the hard-liners resist any accommodation."}
      ]
    },
    {
      text: "The aging Politburo faces a generational crisis. Average age is approaching 70. Career advancement for younger officials means waiting for biological turnover. Gorbachev, Romanov, Grishin, and other younger members jostle for position. Meanwhile, corruption is spreading through the system — the 'cotton affair' in Uzbekistan, scandals in the Caucasus, Brezhnev's own family involved in diamond smuggling.",
      choices: [
        {text: "Support anti-corruption investigations — the party must be cleaned up.", loyalty: 0, cunning: 10, reputation: 10, survival: 0.85, response: "You back Andropov's anti-corruption drive. This earns you the KGB chief's respect and prepares you for the post-Brezhnev era. But anti-corruption campaigns make enemies among the corrupt — who are everywhere."},
        {text: "Protect the existing system of patronage and mutual favors — stability depends on these networks.", loyalty: 10, cunning: 5, reputation: -10, survival: 0.85, response: "You defend the corruption that oils the system. In a sense, informal networks of favor-trading actually make the dysfunctional planned economy work. But defending corruption is increasingly untenable."},
        {text: "Cultivate relationships with the younger generation of leaders — they will inherit power soon.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.90, response: "You invest in the future generation. Gorbachev, in particular, is rising fast as Andropov's protege. Those who build bridges to the incoming generation position themselves to survive the transition."},
        {text: "Propose mandatory retirement ages for senior officials — institutionalize generational renewal.", loyalty: -10, cunning: -5, reputation: 15, survival: 0.60, response: "You suggest forcing the gerontocracy to retire. This is logical, popular with younger officials, and absolutely unacceptable to the Politburo members who would be forced out. Career suicide by committee proposal."}
      ]
    },
    {
      text: "The Soviet Union's technological lag behind the West is becoming impossible to ignore. Computer technology, telecommunications, consumer electronics — all are years behind Western standards. The military is concerned about precision-guided weapons. Efforts to steal Western technology through espionage can supplement but not replace genuine innovation.",
      choices: [
        {text: "Propose expanded technology espionage — stealing Western secrets is faster than developing our own.", loyalty: 5, cunning: 10, reputation: -5, survival: 0.85, response: "You advocate expanding Line X — the KGB's technology theft program. It produces results but cannot substitute for a genuine innovation ecosystem. The Soviet Union becomes a follower rather than a leader in technology."},
        {text: "Argue for reforming the Soviet research system — give scientists more freedom and resources.", loyalty: -5, cunning: 5, reputation: 10, survival: 0.75, response: "You diagnose the real problem: the centralized, bureaucratic research system stifles innovation. Reform requires loosening party control over science — which the leadership resists."},
        {text: "Push for joint ventures with Western technology firms — buy what we cannot build.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.85, response: "You propose technology transfers through commercial partnerships. Some deals are made — Fiat builds a car factory in Togliatti, Pepsi enters the Soviet market. But Western export controls limit the most valuable transfers."},
        {text: "Insist the technology gap is exaggerated — Soviet science leads the world in many fields.", loyalty: 10, cunning: 0, reputation: -5, survival: 0.85, response: "You deny the problem. Soviet science does excel in some areas — space, mathematics, physics — but the gap in computing and information technology is real and growing. Denial prevents the response that is needed."}
      ]
    },
    {
      text: "The Congress approves the Tenth Five-Year Plan. Growth targets have been quietly reduced from previous plans, acknowledging the slowdown without admitting it publicly. Agriculture remains the chronic weak point — the Soviet Union imports massive quantities of grain from the United States and Canada. Each bad harvest is blamed on weather rather than systemic failure.",
      choices: [
        {text: "Accept the reduced targets and focus on achieving them — realistic planning is better than failed ambition.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.90, response: "You become an advocate for achievable targets. In the context of previous plans with wildly unrealistic goals, this modesty is refreshing. But 'realistic' plans in an unreformable system still produce disappointing results."},
        {text: "Argue that reduced targets signal defeatism — we must aim higher to motivate the workforce.", loyalty: 10, cunning: 0, reputation: 0, survival: 0.80, response: "You push for ambitious goals. The leadership likes the rhetoric but knows the reality. Higher targets on paper do not produce higher output in factories. Voluntarism is Khrushchev's ghost haunting Soviet planning."},
        {text: "Propose agricultural reforms — private plots, market incentives, reduced collective farm bureaucracy.", loyalty: -10, cunning: 0, reputation: 10, survival: 0.65, response: "You suggest market elements in agriculture. This echoes Hungarian reforms that have actually improved food supply. But in the Soviet Union, market agriculture is ideologically unacceptable. Your reform ideas die in committee."},
        {text: "Focus on improving supply chains and distribution rather than production — much food is wasted in transport.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.90, response: "You identify a real problem — as much as 30% of Soviet agricultural output spoils before reaching consumers. Improving logistics is politically safe and economically significant. A practical contribution."}
      ]
    }
  ],
  26: [
    {
      text: "The Soviet Union has invaded Afghanistan in December 1979. What was planned as a quick operation to install a reliable government has become a quagmire. The mujahideen resist fiercely with increasing American support. Soviet casualties mount. The international community condemns the invasion. The 1980 Olympics in Moscow are boycotted by Western nations.",
      choices: [
        {text: "Support the Afghan operation fully — we must defend the revolution against imperialist-backed rebels.", loyalty: 10, cunning: 0, reputation: -5, survival: 0.85, response: "You back the war publicly. The military appreciates your support. But Afghanistan becomes the Soviet Vietnam — a bleeding wound that saps morale and resources for nearly a decade."},
        {text: "Privately argue for a negotiated exit — this war cannot be won militarily.", loyalty: -5, cunning: 10, reputation: 10, survival: 0.75, response: "You counsel withdrawal behind closed doors. Some Politburo members share your assessment — including Andropov, who helped initiate the invasion but increasingly regrets it. Your realism positions you well for the future."},
        {text: "Focus on minimizing Soviet casualties — improve equipment, training, and medical support.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.90, response: "You take a practical approach to an impossible situation. Better equipment and tactics can save Soviet lives even if the war cannot be won. The military respects your concern for the troops."},
        {text: "Use Afghanistan to argue for military modernization — we need better helicopters, communications, and special forces.", loyalty: 5, cunning: 10, reputation: 0, survival: 0.85, response: "You channel the Afghan experience into military reform advocacy. Afghanistan does spur improvements in Soviet military capabilities, particularly in special forces and air mobility. Your practical recommendations are valued."}
      ]
    },
    {
      text: "Brezhnev is dying. He can barely function but maintains his grip on power. Andropov maneuvers from the KGB to a Central Committee secretaryship — positioning himself for succession. Chernenko, Brezhnev's loyal aide, is the alternative. Ustinov, the Defense Minister, will be the kingmaker. The succession struggle is underway while the leader still breathes.",
      choices: [
        {text: "Align with Andropov — he represents disciplined reform and anti-corruption.", loyalty: 0, cunning: 15, reputation: 5, survival: 0.90, response: "You back the KGB chief. Andropov becomes General Secretary in November 1982 after Brezhnev's death. Your early support is rewarded with continued access and influence. Andropov's reform agenda begins."},
        {text: "Support Chernenko — loyalty to Brezhnev's choice is the conservative path.", loyalty: 10, cunning: 5, reputation: 0, survival: 0.75, response: "You back Brezhnev's protege. Chernenko loses to Andropov in 1982 but succeeds the dying Andropov in 1984. If you survive both transitions, backing Chernenko eventually pays off — briefly."},
        {text: "Maintain neutrality between factions — serve whoever emerges as leader.", loyalty: 0, cunning: 10, reputation: 0, survival: 0.85, response: "You hedge your bets. The succession involves multiple rounds — Andropov, then Chernenko, then Gorbachev — and neutrality allows you to adapt to each transition. But active supporters of winners are rewarded more than neutral observers."},
        {text: "Build a coalition of younger members who could influence the succession regardless of which elder prevails.", loyalty: -5, cunning: 15, reputation: 5, survival: 0.80, response: "You organize a junior faction. The younger generation — Gorbachev, Ryzhkov, Ligachev — will eventually inherit power. Building relationships with them now is a long-term investment that will pay dividends in 1985."}
      ]
    },
    {
      text: "The Polish crisis continues. Solidarity has been suppressed by martial law, but the underlying problems remain. Reagan's America takes a much harder line than Nixon or Carter — calling the USSR an 'evil empire' and launching a massive arms buildup. Detente is dead. The new Cold War intensifies. How do you advise the leadership to respond?",
      choices: [
        {text: "Match Reagan's buildup — the Soviet military must maintain parity at all costs.", loyalty: 10, cunning: 0, reputation: 0, survival: 0.80, response: "You advocate matching American military spending. But the Soviet economy, one-sixth the size of America's, cannot sustain an arms race at this intensity. The military burden will crack the system."},
        {text: "Pursue a diplomatic offensive — use European peace movements to split NATO.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You propose a sophisticated political strategy targeting European public opinion. The nuclear freeze and peace movements in Western Europe provide leverage. Diplomacy is cheaper than weapons."},
        {text: "Reduce military confrontation and focus resources on fixing the domestic economy.", loyalty: -5, cunning: 10, reputation: 10, survival: 0.75, response: "You argue that the real threat is economic decline, not American missiles. This analysis will be vindicated when Gorbachev adopts exactly this priority. But in 1981, the military-industrial complex rejects any talk of retrenchment."},
        {text: "Wait Reagan out — American political cycles will eventually produce a more accommodating president.", loyalty: 5, cunning: 10, reputation: 0, survival: 0.85, response: "You counsel patience. Reagan cannot last forever, and American politics tend to oscillate. In fact, Reagan himself will eventually pursue arms control in his second term. Strategic patience has merit."}
      ]
    },
    {
      text: "The economy is stagnating seriously. Growth is near zero. Agricultural production cannot feed the population without massive grain imports. Consumer goods quality is abysmal. The black market thrives. 'Blat' — the system of personal connections and favors — is how most people actually obtain goods and services. Official economic statistics are increasingly fictional.",
      choices: [
        {text: "Acknowledge the crisis privately and push for emergency economic measures.", loyalty: 0, cunning: 10, reputation: 10, survival: 0.80, response: "You present alarming economic data to the Politburo. Some members are receptive — especially Andropov. But the system's inertia is enormous. Emergency measures require a political will that the gerontocracy lacks."},
        {text: "Maintain the optimistic facade — admitting economic failure would undermine the system's legitimacy.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.85, response: "You continue the pretense. The gap between official optimism and lived reality grows wider. Public cynicism deepens. But maintaining the fiction is what the leadership demands."},
        {text: "Propose limited market experiments — special economic zones or cooperative enterprises.", loyalty: -5, cunning: 10, reputation: 10, survival: 0.70, response: "You suggest market reforms similar to what Deng Xiaoping is implementing in China. The idea is ahead of its time in the Soviet context — Andropov will tinker with reforms, Gorbachev will attempt them in earnest."},
        {text: "Focus on labor discipline — crack down on absenteeism, alcoholism, and theft of state property.", loyalty: 10, cunning: 10, reputation: 0, survival: 0.90, response: "You propose Andropov's solution: tighten discipline without changing the system. Police raid cinemas and bathhouses during working hours to catch shirkers. It produces a brief uptick in productivity but changes nothing fundamental."}
      ]
    },
    {
      text: "Corruption has penetrated every level of the system. The 'cotton affair' in Uzbekistan reveals that the entire republic has been reporting falsified cotton production figures for years, with officials pocketing the difference. Brezhnev's own son-in-law is involved in diamond smuggling. The Minister of Interior is implicated in bribery. Andropov's KGB compiles dossiers on the corrupt.",
      choices: [
        {text: "Support Andropov's anti-corruption investigations fully — the system must be cleaned up.", loyalty: 0, cunning: 10, reputation: 10, survival: 0.85, response: "You align with the anti-corruption drive. When Andropov becomes General Secretary, your early support is remembered. But anti-corruption campaigns in a systemically corrupt system create enemies everywhere."},
        {text: "Protect your own network from investigation — ensure your people are clean or at least hidden.", loyalty: 5, cunning: 15, reputation: -5, survival: 0.90, response: "You shield your allies while supporting the principle of anti-corruption. Selective enforcement is the Soviet way — everyone is guilty of something, so the question is who gets investigated."},
        {text: "Argue that corruption is a symptom of systemic failure — the system itself must be reformed.", loyalty: -10, cunning: 5, reputation: 15, survival: 0.60, response: "You diagnose the root cause. Corruption thrives because the planned economy cannot meet people's needs through legal channels. This analysis is correct but implies the entire system needs restructuring — a politically explosive conclusion."},
        {text: "Blame local officials for corruption while defending the central system — bad apples, not a bad barrel.", loyalty: 10, cunning: 10, reputation: 0, survival: 0.90, response: "You isolate the problem as one of individual morality rather than systemic failure. This is the comfortable fiction that allows the leadership to punish individuals without confronting structural issues."}
      ]
    },
    {
      text: "A Korean Air Lines Boeing 747 has been shot down by a Soviet fighter jet after straying into Soviet airspace, killing all 269 people aboard. The international outcry is enormous. The Soviet military initially denies the incident, then claims the plane was on a spy mission. You participate in the crisis response discussion within the leadership.",
      choices: [
        {text: "Support the military's position — the plane was on an intelligence mission and we acted correctly.", loyalty: 10, cunning: 0, reputation: -10, survival: 0.80, response: "You back the military's story. The propaganda battle is lost — the black box recordings will eventually prove the shootdown was a tragic error. Your support for the cover-up damages your credibility internationally."},
        {text: "Advocate for a more nuanced response — acknowledge the tragedy while explaining our air defense concerns.", loyalty: 0, cunning: 15, reputation: 5, survival: 0.85, response: "You counsel a more sophisticated public response. Some acknowledgment of tragedy, combined with legitimate concerns about airspace violations, would serve Soviet interests better than crude denial."},
        {text: "Use the crisis to argue for better military communication systems to prevent future incidents.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.90, response: "You turn the crisis into a technical recommendation. Better radar identification systems and military hotlines could prevent repeats. Practical problem-solving during a crisis marks you as someone who thinks clearly under pressure."},
        {text: "Blame American provocations — the US routinely uses civilian aircraft to test our defenses.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.85, response: "You advance the conspiracy theory that the US deliberately sent the aircraft into Soviet airspace. This narrative has no evidence but serves the domestic propaganda need to shift blame away from Soviet actions."}
      ]
    },
    {
      text: "Andropov, though mortally ill, has begun reforms. He cracks down on labor discipline, arrests corrupt officials, and hints at economic restructuring. Gorbachev is his protege and likely successor. But Chernenko and the Brezhnev old guard resist. The power struggle is between reformers and conservatives. Andropov will die in February 1984 after only fifteen months in power.",
      choices: [
        {text: "Strongly support Andropov's reform agenda — discipline and restructuring are essential.", loyalty: 10, cunning: 10, reputation: 5, survival: 0.85, response: "You become an Andropov loyalist. His death disrupts the reform program, but his legacy shapes the future. Gorbachev will carry forward many of Andropov's ideas. Your early commitment to reform positions you well."},
        {text: "Support reforms cautiously — align with Andropov but maintain ties to the Chernenko faction.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You hedge your bets between the reformers and the old guard. Chernenko succeeds Andropov, then Gorbachev succeeds Chernenko. Your careful positioning allows you to survive both transitions."},
        {text: "Resist the reforms — they threaten the stability that has kept the system functioning.", loyalty: 0, cunning: 5, reputation: -5, survival: 0.75, response: "You join the conservative resistance. When Chernenko briefly succeeds Andropov, your position strengthens. But Gorbachev's accession in 1985 marginalizes the conservatives permanently."},
        {text: "Use Andropov's anti-corruption drive to eliminate your own political rivals.", loyalty: 5, cunning: 10, reputation: -10, survival: 0.85, response: "You weaponize the reforms. Anti-corruption investigations become tools for settling scores. This is common practice — every reform movement is also a power struggle. Effective but cynical."}
      ]
    },
    {
      text: "The Soviet military leadership is increasingly worried about NATO's Pershing II missiles being deployed in Western Europe. Flight time to Moscow would be under ten minutes. Some generals argue for a preemptive strike doctrine. The Able Archer 83 NATO exercise triggers genuine war fears in Moscow. The world comes closer to nuclear war than most people realize.",
      choices: [
        {text: "Support an aggressive response — accelerate deployment of SS-20 missiles targeting Western Europe.", loyalty: 10, cunning: 0, reputation: -5, survival: 0.80, response: "You back the military's escalation. The SS-20 deployments triggered the Pershing response in the first place, creating an action-reaction spiral. More missiles do not make Moscow safer but the military-industrial complex is satisfied."},
        {text: "Advocate for arms control negotiations to address the Euromissile crisis.", loyalty: 5, cunning: 15, reputation: 10, survival: 0.90, response: "You push for diplomacy. The INF Treaty negotiated under Gorbachev will eventually eliminate an entire class of nuclear weapons. Your early advocacy for negotiation positions you well for the diplomatic breakthroughs ahead."},
        {text: "Improve intelligence capabilities to reduce the risk of accidental war from misread signals.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You focus on reducing the chance of catastrophic miscalculation. Stanislav Petrov's decision not to report a false missile alarm may have saved the world in September 1983. Better systems could prevent such close calls."},
        {text: "Argue that nuclear war is unwinnable and Soviet doctrine should explicitly recognize this.", loyalty: -5, cunning: 5, reputation: 10, survival: 0.75, response: "You advocate a fundamental shift in nuclear doctrine. This view will prevail under Gorbachev, who declares that nuclear war can have no winners. Your position is ahead of its time but will be vindicated within a few years."}
      ]
    }
  ],
  27: [
    {
      text: "Gorbachev's anti-alcohol campaign is in full swing. Vineyards are being ripped up, distilleries closed, and alcohol sales restricted. The campaign aims to address the genuine crisis of Soviet alcoholism but slashes government revenue — vodka taxes were a major income source. Sugar disappears from stores as citizens make moonshine. The campaign is deeply unpopular.",
      choices: [
        {text: "Enforce the campaign vigorously — alcoholism is destroying Soviet society and productivity.", loyalty: 10, cunning: 0, reputation: -5, survival: 0.80, response: "You implement the campaign with zeal. Health indicators actually improve — life expectancy rises, workplace accidents decline. But the fiscal damage and public resentment are enormous. Gorbachev will quietly abandon the campaign."},
        {text: "Implement the campaign selectively — show compliance without destroying local wine industries.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You create the appearance of enforcement while protecting economically important producers. Georgian winemakers and Baltic breweries survive through creative interpretation of the rules. Pragmatic officials everywhere do the same."},
        {text: "Privately advise Gorbachev that the campaign is counterproductive — it costs revenue and creates resentment.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.80, response: "You tell the leader what he does not want to hear. Ligachev, who champions the campaign, considers you an enemy. But Gorbachev eventually reaches the same conclusion and the campaign is scaled back."},
        {text: "Use the campaign to demonstrate your loyalty to Gorbachev's reform agenda more broadly.", loyalty: 10, cunning: 10, reputation: 0, survival: 0.85, response: "You frame the anti-alcohol campaign as part of the broader perestroika project, linking it to labor discipline and moral renewal. This shows Gorbachev you are a committed reformer, even on unpopular measures."}
      ]
    },
    {
      text: "Chernobyl has exploded. The initial government response was denial and delay — local officials were not evacuated for 36 hours. The radiation cloud spreads across Europe. Gorbachev is furious at being lied to by subordinates. The disaster becomes a powerful argument for glasnost — if the system cannot tell the truth about a nuclear catastrophe, what can it tell the truth about?",
      choices: [
        {text: "Champion full transparency about Chernobyl — use it to accelerate glasnost across all areas.", loyalty: 10, cunning: 5, reputation: 10, survival: 0.80, response: "You push for radical openness. The truth about Chernobyl is devastating but its release strengthens Gorbachev's reform hand. Glasnost gains unstoppable momentum. But total transparency will eventually unravel the Soviet narrative itself."},
        {text: "Manage the information carefully — release enough truth to satisfy critics without causing panic.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.85, response: "You advocate controlled transparency. Release technical details about the disaster while managing the political narrative. This middle ground is difficult to maintain as journalists and scientists demand more information."},
        {text: "Focus on the practical response — evacuation, decontamination, medical treatment, reactor containment.", loyalty: 5, cunning: 10, reputation: 10, survival: 0.90, response: "You throw yourself into disaster management rather than political positioning. The liquidators need leadership, the evacuees need housing, the contaminated zone needs management. Practical competence is your shield."},
        {text: "Argue that Chernobyl is being exploited by enemies of socialism to discredit the Soviet system.", loyalty: -5, cunning: 0, reputation: -10, survival: 0.65, response: "You dismiss the disaster's significance. This puts you on the wrong side of history and the wrong side of Gorbachev. The conservative attempt to minimize Chernobyl fails completely as the radiation refuses to be denied."}
      ]
    },
    {
      text: "The old guard is being pushed out. Grishin, Romanov, Tikhonov, Kunaev — the Brezhnev-era holdovers are replaced by Gorbachev allies. The December 1986 riots in Alma-Ata (now Almaty) follow Kunaev's replacement with a Russian, revealing the explosive potential of the nationalities question. Gorbachev has underestimated how perestroika will unleash ethnic tensions.",
      choices: [
        {text: "Support the personnel changes — the old guard must go for reform to succeed.", loyalty: 10, cunning: 5, reputation: 5, survival: 0.85, response: "You back Gorbachev's cadre revolution. Fresh blood in the leadership accelerates reform. But the Alma-Ata riots warn that replacing national leaders with outsiders has consequences."},
        {text: "Warn that removing national cadres too quickly will trigger ethnic unrest.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.85, response: "You raise the nationalities dimension of the personnel changes. The Alma-Ata riots vindicate your warning. Gorbachev begins to handle republic leadership changes more carefully — but the nationalities genie is already out of the bottle."},
        {text: "Position yourself as a bridge between the old guard and the reformers — represent continuity amid change.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You present yourself as someone who understands both the old system and the need for reform. In a time of rapid change, officials who can manage transitions without ruptures are invaluable."},
        {text: "Align with the departing old guard — Gorbachev's reforms are reckless and destabilizing.", loyalty: -10, cunning: 0, reputation: -5, survival: 0.60, response: "You defend the old order. As Brezhnev-era officials are marginalized, your loyalty to them becomes a liability. Gorbachev has the momentum and the Politburo majority. Swimming against the current is exhausting."}
      ]
    },
    {
      text: "Glasnost is releasing a flood of previously suppressed history. The truth about the Molotov-Ribbentrop Pact's secret protocols, the Katyn massacre, the full scale of Stalin's Terror — all are being published in Soviet media for the first time. The historical commission headed by Yakovlev challenges the founding myths of the Soviet system. Conservatives are alarmed.",
      choices: [
        {text: "Support the historical revelations — the truth, however painful, must be confronted.", loyalty: 5, cunning: 5, reputation: 15, survival: 0.80, response: "You champion historical truth. This earns you respect among the intelligentsia and the reformist wing. But every revelation undermines the system's legitimacy further. Where does the truth-telling end?"},
        {text: "Argue that historical revelations should be gradual and controlled — too much truth too fast is destabilizing.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.85, response: "You counsel managed disclosure. Some truths — like the Katyn massacre — are so explosive that releasing them requires diplomatic preparation. Your caution is sensible but events outrun your careful timetable."},
        {text: "Warn that destroying Soviet historical myths will destroy Soviet identity itself.", loyalty: -5, cunning: 5, reputation: 0, survival: 0.70, response: "You voice the conservative fear. If everything the party taught was a lie, what legitimacy remains? This is the core question that glasnost raises and never answers. Your warning is prophetic but unheeded."},
        {text: "Use the historical openness to commission a proper history of your own region or institution.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.85, response: "You channel glasnost into constructive historical work in your area. Local histories, institutional memoirs, and regional archives open up. This productive engagement with the past earns you respect without taking extreme positions."}
      ]
    },
    {
      text: "Yeltsin, the brash Moscow party chief, delivers a shocking speech at the October 1987 Central Committee plenum criticizing the pace of reform and attacking Ligachev personally. Gorbachev is furious at the breach of discipline. Yeltsin is publicly humiliated and removed from his post. But his rebellion makes him a popular hero — the man who dared to challenge the system.",
      choices: [
        {text: "Join the denunciation of Yeltsin — his behavior was a violation of party discipline.", loyalty: 10, cunning: 5, reputation: -5, survival: 0.85, response: "You participate in the ritual condemnation. Almost everyone does. But Yeltsin's public humiliation transforms him from a party functionary into a populist martyr. Those who attacked him most viciously will pay a price when he rises to supreme power."},
        {text: "Remain silent during the denunciation — neither attack nor defend Yeltsin.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.90, response: "You say nothing during the plenum. The safest position in a factional fight whose outcome is uncertain. Yeltsin is down now but may rise again. Your silence preserves all options."},
        {text: "Express limited sympathy for Yeltsin's frustrations while condemning his methods.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.80, response: "You thread the needle — acknowledging that reform could move faster while criticizing Yeltsin's undisciplined approach. This nuanced position satisfies neither camp fully but offends neither completely."},
        {text: "Reach out to Yeltsin privately after his removal — offer support and counsel.", loyalty: -10, cunning: 10, reputation: 10, survival: 0.70, response: "You make contact with the disgraced Yeltsin. This is risky while he is in disgrace but potentially invaluable if he returns to power. By 1991, Yeltsin will be President of Russia. Early supporters will be rewarded."}
      ]
    },
    {
      text: "The INF Treaty negotiations with Reagan are reaching their conclusion. Gorbachev has agreed to eliminate all intermediate-range nuclear missiles — a concession that horrifies the military. The Soviet side gives up more weapons than the American side. Hard-liners call it a surrender. Gorbachev sees it as the beginning of ending the arms race that is bankrupting the country.",
      choices: [
        {text: "Support the INF Treaty — ending the nuclear arms race is essential for economic reform.", loyalty: 10, cunning: 10, reputation: 5, survival: 0.85, response: "You back Gorbachev's arms control vision. The treaty is signed in December 1987. Resources freed from the military can theoretically fund economic reform. Your support for the treaty marks you as a committed reformer."},
        {text: "Express concerns about asymmetric concessions — we are giving up more than the Americans.", loyalty: -5, cunning: 5, reputation: 0, survival: 0.75, response: "You voice the military's objections. The numbers do favor America — the Soviets destroy more missiles. But Gorbachev argues that reducing nuclear danger benefits everyone regardless of arithmetic. Your objections are overruled."},
        {text: "Advocate for linking arms control to economic modernization — peace should fund prosperity.", loyalty: 5, cunning: 10, reputation: 10, survival: 0.85, response: "You build the bridge between foreign policy and domestic reform. If military spending decreases, consumer goods and technology can increase. This 'peace dividend' argument resonates with the public and the reformers."},
        {text: "Support the treaty publicly while quietly reassuring military leaders that their core interests will be protected.", loyalty: 5, cunning: 15, reputation: 0, survival: 0.90, response: "You manage both constituencies — reformers and the military. Arms control proceeds while the strategic nuclear deterrent remains intact. Being a bridge between competing power centers is the most valuable skill in a time of change."}
      ]
    },
    {
      text: "Nationality tensions are erupting. Armenians in Nagorno-Karabakh demand unification with Armenia. Violence breaks out between Armenians and Azerbaijanis. The Baltic republics form Popular Fronts demanding autonomy. In Moscow, Gorbachev is stunned — he did not expect perestroika to unleash nationalist movements. The Soviet nationalities policy, built on suppressed tensions, is unraveling.",
      choices: [
        {text: "Advocate for military force to suppress nationalist movements — the Union must be preserved.", loyalty: 5, cunning: 0, reputation: -10, survival: 0.70, response: "You call for a crackdown. Force is used in Tbilisi in April 1989, killing demonstrators. The violence backfires catastrophically, accelerating independence movements. Military solutions to political problems fail."},
        {text: "Propose genuine federalism — give republics real autonomy within a reformed Union.", loyalty: 5, cunning: 10, reputation: 10, survival: 0.80, response: "You advocate the solution Gorbachev himself eventually proposes — a new Union Treaty with genuine republican sovereignty. But events outrun the negotiators. By the time the treaty is ready, several republics want full independence."},
        {text: "Focus on your own republic's interests — position yourself as a defender of local rights.", loyalty: -5, cunning: 15, reputation: 10, survival: 0.85, response: "You pivot from Soviet politics to republican politics. Many party officials across the USSR make exactly this transition — becoming national leaders of newly sovereign states. It is the most successful survival strategy for the end of the USSR."},
        {text: "Argue that economic reform will address nationalist grievances — prosperity will hold the Union together.", loyalty: 5, cunning: 5, reputation: 0, survival: 0.75, response: "You misdiagnose the problem. National movements are driven by identity and history, not just economics. Even prosperous republics like the Baltics want independence. Your economic solution addresses the wrong question."}
      ]
    },
    {
      text: "The withdrawal from Afghanistan is underway. Soviet troops are coming home to a mixed reception. The war is widely seen as a mistake, though no one in the leadership takes personal responsibility. Veterans return to a society that does not understand their experience. The parallel to America's Vietnam is obvious. Gorbachev wants to close the chapter quickly.",
      choices: [
        {text: "Support a quiet, dignified withdrawal — no victory parades, no public recriminations.", loyalty: 5, cunning: 15, reputation: 5, survival: 0.90, response: "You manage the political aspects of withdrawal. No blame is assigned, no lessons are publicly drawn, no officials are punished. The Afghan war is buried as quickly as possible. This serves the leadership's need for closure."},
        {text: "Advocate for a full public accounting of the Afghan war — who decided, why, and what went wrong.", loyalty: -5, cunning: 0, reputation: 15, survival: 0.70, response: "You push for transparency about the war. Glasnost should extend to military failures. The military and security services resist any investigation. Your call for accountability makes powerful enemies in the defense establishment."},
        {text: "Focus on supporting Afghan veterans — they deserve recognition and assistance.", loyalty: 5, cunning: 10, reputation: 10, survival: 0.85, response: "You champion the forgotten veterans. Housing, medical care, employment assistance — the returning soldiers need practical support. Your advocacy is genuinely humanitarian and politically safe."},
        {text: "Use the Afghan withdrawal to argue for a broader retreat from Third World commitments.", loyalty: 0, cunning: 10, reputation: 5, survival: 0.80, response: "You draw strategic lessons from Afghanistan. The USSR can no longer afford to maintain a global empire of client states. Soviet aid to Cuba, Ethiopia, Angola, and Vietnam should be reduced. This argument gains traction as the economy deteriorates."}
      ]
    }
  ],
  28: [
    {
      text: "The Berlin Wall has fallen. Eastern European Communist governments collapse one after another — Poland, Hungary, East Germany, Czechoslovakia, Bulgaria, Romania. Gorbachev refuses to use military force to save them. The Brezhnev Doctrine is dead. Within the Soviet leadership, conservatives are horrified while reformers celebrate. The Warsaw Pact is disintegrating.",
      choices: [
        {text: "Accept the loss of Eastern Europe as inevitable — focus on reforming the Soviet Union itself.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.80, response: "You take the pragmatic view. The Eastern European empire was always a burden as much as an asset. Without it, the USSR can focus resources on its own transformation. But the psychological blow to Soviet identity is enormous."},
        {text: "Demand that Gorbachev intervene to save the socialist governments — or at least negotiate an orderly transition.", loyalty: -5, cunning: 5, reputation: 0, survival: 0.65, response: "You argue for intervention or at least leverage. Gorbachev refuses — he will not use force to maintain an empire. The conservative position has no path to implementation without a leader willing to order the tanks."},
        {text: "Use the Eastern European changes as a model for Soviet reform — democracy and market economics can work.", loyalty: 5, cunning: 5, reputation: 10, survival: 0.75, response: "You point to Eastern European transitions as inspiration. But the Soviet situation is more complex — the nationalities question means reform could mean dissolution. Eastern Europe's revolutions are both an inspiration and a warning."},
        {text: "Begin planning for a post-Soviet future — the Union itself may not survive.", loyalty: -10, cunning: 15, reputation: 0, survival: 0.85, response: "You see the writing on the wall. If Eastern Europe can break free, why not the Baltic states, Ukraine, or Georgia? You begin positioning for a world without the USSR — building contacts, securing assets, planning transitions."}
      ]
    },
    {
      text: "The Baltic republics — Estonia, Latvia, Lithuania — are demanding independence. Lithuania has declared sovereignty. Gorbachev imposes an economic blockade. In January 1991, Soviet troops will kill civilians at the Vilnius television tower. The question is whether the Union can survive the loss of any republic. If the Baltics leave, who follows?",
      choices: [
        {text: "Support Baltic independence — these nations were illegally annexed and have the right to leave.", loyalty: -15, cunning: 5, reputation: 15, survival: 0.75, response: "You acknowledge the historical injustice of the 1940 annexation. This position aligns with international law and glasnost's commitment to truth. But it implies the Soviet Union itself was built on illegitimate foundations."},
        {text: "Oppose independence but support genuine autonomy within a reformed Union.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.75, response: "You try to save the Union through federalism. This is Gorbachev's own position. But the Baltics have moved beyond autonomy — they want full independence. Your compromise satisfies neither side."},
        {text: "Argue that economic interdependence makes independence impractical — the Baltics need the Soviet market.", loyalty: 5, cunning: 5, reputation: 0, survival: 0.70, response: "You make the economic case for Union. The Baltics are indeed integrated into the Soviet economy. But national sentiment overrides economic calculation. The Baltics prefer poverty with freedom to prosperity without it."},
        {text: "Support the use of force to prevent secession — the Union's territorial integrity must be defended.", loyalty: 10, cunning: -5, reputation: -15, survival: 0.55, response: "You advocate military force. The January 1991 violence in Vilnius and Riga backfires catastrophically — it strengthens independence movements and discredits the Soviet government internationally. Force cannot hold the Union together."}
      ]
    },
    {
      text: "Article 6 of the Soviet Constitution — guaranteeing the Communist Party's monopoly on power — has been abolished. Multi-party elections are now legal. The Congress of People's Deputies has become a genuine parliament with televised debates. Communist Party membership is collapsing as people tear up their party cards. The party's 19 million members are bleeding away.",
      choices: [
        {text: "Embrace multi-party democracy — transform the Communist Party into a competitive political party.", loyalty: 0, cunning: 10, reputation: 10, survival: 0.80, response: "You advocate transformation. Some European Communist parties successfully became social-democratic parties. But the CPSU is too associated with repression and failure to rebrand effectively. The party's days are numbered."},
        {text: "Fight to preserve Article 6 — without the party's leading role, the country will fall apart.", loyalty: 10, cunning: 0, reputation: -10, survival: 0.55, response: "You defend the party monopoly. But the vote is lost — even most party members recognize that the monopoly is unsustainable. Your defense of the old order marks you as unreformable."},
        {text: "Begin building a new political organization — a reform party that can compete in free elections.", loyalty: -10, cunning: 15, reputation: 5, survival: 0.85, response: "You look beyond the CPSU and begin organizing a new political vehicle. Several post-Soviet parties will emerge from this period of ferment. Those who organize early have an advantage in the new democratic landscape."},
        {text: "Focus on maintaining your personal power base regardless of what happens to the party as an institution.", loyalty: -5, cunning: 15, reputation: -5, survival: 0.90, response: "You separate your personal political survival from the party's institutional survival. Power resides in networks, resources, and relationships — not party cards. Many Soviet officials successfully transition to post-Soviet power without ever ceasing to be powerful."}
      ]
    },
    {
      text: "Yeltsin has been elected President of the Russian Soviet Federative Socialist Republic on a wave of populist support. He dramatically resigns from the Communist Party at this Congress and walks out of the hall. The symbolism is devastating — the most powerful politician in the largest Soviet republic has abandoned the party. Other delegates consider following him.",
      choices: [
        {text: "Follow Yeltsin out of the hall — the party is finished and the future belongs to Russia.", loyalty: -20, cunning: 10, reputation: 10, survival: 0.80, response: "You join the walkout. It is a dramatic gesture that burns all bridges. If the Communist Party somehow survives, you are finished. But the party does not survive, and those who left early position themselves for the new Russia."},
        {text: "Stay in the hall and denounce Yeltsin as a traitor and demagogue.", loyalty: 15, cunning: 0, reputation: -5, survival: 0.55, response: "You attack the man who will dominate Russian politics for the next decade. When the USSR dissolves and Yeltsin becomes President of independent Russia, those who denounced him most vocally are marginalized."},
        {text: "Stay but remain silent — watch which way the wind blows before committing.", loyalty: 0, cunning: 15, reputation: 0, survival: 0.80, response: "You stay seated but keep your mouth shut. The hall is in chaos — some delegates leave, others stay, many are uncertain. In a moment of maximum confusion, gathering information is wiser than taking action."},
        {text: "Propose a reform resolution that addresses Yeltsin's grievances while preserving party unity.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.70, response: "You try to save the situation with a compromise. But the time for compromise has passed. Yeltsin is not interested in reforming the party — he is interested in replacing it. Your reasonable proposal is overtaken by events."}
      ]
    },
    {
      text: "The Soviet economy is in freefall. Inflation is rising, store shelves are empty, and the ruble is collapsing. Gorbachev's economic advisors propose the '500 Days' program — a rapid transition to a market economy. Conservatives block it. The result is the worst of both worlds: the planned economy is dismantled without a market economy replacing it. Economic chaos fuels political crisis.",
      choices: [
        {text: "Support the 500 Days program — radical reform is the only way out of the crisis.", loyalty: -5, cunning: 5, reputation: 10, survival: 0.75, response: "You back Shatalin and Yavlinsky's reform plan. It is bold, risky, and never implemented. Gorbachev vacillates between radical reform and conservative caution, paralyzing economic policy. Your support for radical reform marks you as forward-thinking but powerless."},
        {text: "Argue for gradual reform — shock therapy will destroy the economy and create mass unemployment.", loyalty: 5, cunning: 10, reputation: 5, survival: 0.80, response: "You advocate a slower transition. This cautious approach appeals to those who fear the social costs of rapid change. But gradualism requires political stability that no longer exists. The economic situation deteriorates regardless of which approach is chosen."},
        {text: "Focus on securing essential supplies for your region — food, fuel, medicine — regardless of which reform path is chosen.", loyalty: 0, cunning: 15, reputation: 5, survival: 0.90, response: "You focus on the immediate practical crisis. While Moscow debates economic theory, people need to eat. Regional leaders who keep their populations fed maintain popular support regardless of the political chaos above them."},
        {text: "Begin privatizing state assets in your sphere of control — position yourself for the transition to capitalism.", loyalty: -10, cunning: 15, reputation: -15, survival: 0.90, response: "You start the process of 'spontaneous privatization' — converting control of state enterprises into personal ownership. This is the origin story of many Russian oligarchs. Deeply corrupt but extraordinarily lucrative for those with the right positions."}
      ]
    },
    {
      text: "Conservative forces are coalescing. Military officers, KGB officials, and party hardliners openly discuss the need to 'restore order.' The Soyuz parliamentary group demands a crackdown. Defense Minister Yazov, KGB chief Kryuchkov, and Vice President Yanayev form an inner circle. They will launch a coup attempt against Gorbachev in August 1991. The signs are visible to those paying attention.",
      choices: [
        {text: "Join the conservative movement — the country is falling apart and strong measures are needed.", loyalty: 10, cunning: -5, reputation: -10, survival: 0.50, response: "You align with the plotters. The August 1991 coup will fail within three days. Those associated with it face arrest and permanent disgrace. Yeltsin bans the Communist Party. You chose the wrong side of history."},
        {text: "Warn Gorbachev that a coup is being planned — the conservatives are organizing against him.", loyalty: 5, cunning: 10, reputation: 10, survival: 0.75, response: "You try to alert the leader. Gorbachev receives many such warnings and dismisses them — he trusts his appointees. When the coup happens, your warning was proved right but it was not heeded. Your loyalty to Gorbachev does not protect you from the chaos that follows."},
        {text: "Distance yourself from both the plotters and Gorbachev — prepare for any outcome.", loyalty: -5, cunning: 15, reputation: 0, survival: 0.85, response: "You position yourself for maximum flexibility. When the coup launches, you wait to see who wins before declaring a position. This cold calculation saves you from the fate of the plotters without requiring any courage."},
        {text: "Begin building relationships with Yeltsin's Russian government — sovereign Russia will outlast the USSR.", loyalty: -15, cunning: 15, reputation: 5, survival: 0.90, response: "You pivot to the institution that will inherit power — the Russian Federation. When the coup fails and the USSR dissolves, those already embedded in Russian structures hold the cards. The most far-sighted Soviet officials have already made this transition."}
      ]
    },
    {
      text: "The final session of the Congress debates the party's future. Some propose transforming into a social-democratic party. Others want to split into reformist and conservative wings. National delegations from the Baltic republics announce they are forming independent parties. The Ukrainian delegation is divided. The Russian delegation is in chaos after Yeltsin's departure.",
      choices: [
        {text: "Propose splitting the party into a reformist social-democratic party and a traditional communist party.", loyalty: -5, cunning: 10, reputation: 5, survival: 0.75, response: "You suggest a formal division. This would allow both tendencies to compete democratically. The proposal has logic but neither wing has the organizational capacity or political base to succeed independently. The CPSU simply dissolves."},
        {text: "Argue passionately for unity — the party must reform together or die together.", loyalty: 10, cunning: 0, reputation: 5, survival: 0.65, response: "You make an emotional appeal for party unity. The speech is moving but futile. The forces tearing the party apart are stronger than any speech can counter. The CPSU will be suspended after the August coup and never reconstituted."},
        {text: "Use the chaos to secure control of party assets in your region — buildings, funds, media outlets.", loyalty: -10, cunning: 15, reputation: -10, survival: 0.90, response: "You grab what you can. Party real estate, bank accounts, printing presses, and media outlets are enormously valuable. Those who control party assets at the moment of dissolution often keep them. A cynical but effective survival strategy."},
        {text: "Announce your own resignation from the party and call for a new democratic political movement.", loyalty: -15, cunning: 10, reputation: 15, survival: 0.80, response: "You make your own dramatic exit, calling for democratic renewal. This positions you as a reformer in the post-Soviet landscape. Many former party members successfully reinvent themselves as democrats, liberals, or nationalists."}
      ]
    },
    {
      text: "The Congress ends. It is the last gathering of the Communist Party of the Soviet Union. Within eighteen months, the party will be banned and the USSR dissolved. Gorbachev will resign as President of a country that no longer exists. Fifteen new nations will emerge from the rubble. The seventy-three-year Soviet experiment is over. What is your final move?",
      choices: [
        {text: "Stay with Gorbachev to the bitter end — help manage the dissolution with dignity.", loyalty: 10, cunning: 0, reputation: 10, survival: 0.65, response: "You remain loyal to the last Soviet leader. Gorbachev's final months are a study in dignified decline. He transfers the nuclear briefcase to Yeltsin on December 25, 1991. Your loyalty is admirable but leaves you in the political wilderness of the new era."},
        {text: "Transition to Yeltsin's Russia — the future belongs to sovereign states, not the Union.", loyalty: -10, cunning: 15, reputation: 0, survival: 0.85, response: "You join the winning side. Yeltsin's Russia inherits the Soviet Union's UN seat, nuclear arsenal, and most of its territory. Former Soviet officials who transition smoothly to the Russian government retain power and influence."},
        {text: "Return to your home republic and build a political career in the newly independent nation.", loyalty: -10, cunning: 10, reputation: 10, survival: 0.85, response: "You go home. In the newly independent states, former Soviet officials often become national leaders — Kravchuk in Ukraine, Shevardnadze in Georgia, Nazarbayev in Kazakhstan. Local knowledge and networks translate into post-Soviet power."},
        {text: "Convert your political connections into business opportunities — the age of oligarchs is beginning.", loyalty: -15, cunning: 20, reputation: -15, survival: 0.95, response: "You follow the money. The privatization of Soviet state assets creates the greatest transfer of wealth in history. Former officials who position themselves at the intersection of state power and private capital become fabulously wealthy. The Politburo game ends; the oligarch game begins."}
      ]
    }
  ],
};
